import type { BibleVerse } from '../bibleData';

export const GENESIS_CH13_31: Record<number, BibleVerse[]> = {
  13: [
    { v: 1, en: 'And Abram went up out of Egypt, he, and his wife, and all that he had, and Lot with him, into the south.', pt: 'Subiu, pois, Abrão do Egito para o sul, ele e sua mulher e tudo o que tinha, e Ló com ele.' },
    { v: 2, en: 'And Abram was very rich in cattle, in silver, and in gold.', pt: 'E Abrão era mui rico em gado, em prata e em ouro.' },
    { v: 3, en: 'And he went on his journeys from the south even to Bethel, unto the place where his tent had been at the beginning, between Bethel and Hai.', pt: 'E foi em suas jornadas desde o sul até Betel, até ao lugar onde a sua tenda estivera no princípio, entre Betel e Ai.' },
    { v: 4, en: 'Unto the place of the altar, which he had made there at the first: and there Abram called on the name of the LORD.', pt: 'Ao lugar do altar que fizera ali no princípio; e ali Abrão invocou o nome do Senhor.' },
    { v: 5, en: 'And Lot also, which went with Abram, had flocks, and herds, and tents.', pt: 'E também Ló, que ia com Abrão, tinha ovelhas, e bois, e tendas.' },
    { v: 6, en: 'And the land was not able to bear them, that they might dwell together: for their substance was great, so that they could not dwell together.', pt: 'E a terra não os podia conter para habitarem juntos, porque os seus bens eram muitos, e não podiam habitar juntos.' },
    { v: 7, en: 'And there was a strife between the herdmen of Abram\'s cattle and the herdmen of Lot\'s cattle: and the Canaanite and the Perizzite dwelled then in the land.', pt: 'E havia contenda entre os pastores do gado de Abrão e os pastores do gado de Ló; e o cananeu e o ferezeu habitavam então naquela terra.' },
    { v: 8, en: 'And Abram said unto Lot, Let there be no strife, I pray thee, between me and thee, and between my herdmen and thy herdmen; for we be brethren.', pt: 'Então disse Abrão a Ló: Rogo-te que não haja contenda entre mim e ti, e entre os meus pastores e os teus pastores, porque somos irmãos.' },
    { v: 9, en: 'Is not the whole land before thee? separate thyself, I pray thee, from me: if thou wilt take the left hand, then I will go to the right; or if thou depart to the right hand, then I will go to the left.', pt: 'Não está toda a terra diante de ti? Separa-te, pois, de mim; se tu fores para a esquerda, eu irei para a direita; e se tu fores para a direita, eu irei para a esquerda.' },
    { v: 10, en: 'And Lot lifted up his eyes, and beheld all the plain of Jordan, that it was well watered every where, before the LORD destroyed Sodom and Gomorrah, even as the garden of the LORD, like the land of Egypt, as thou comest unto Zoar.', pt: 'E Ló levantou os seus olhos, e viu toda a planície do Jordão, que toda ela era regada, antes de o Senhor destruir Sodoma e Gomorra, como o jardim do Senhor, como a terra do Egito, quando se vai para Zoar.' },
    { v: 11, en: 'Then Lot chose him all the plain of Jordan; and Lot journeyed east: and they separated themselves the one from the other.', pt: 'Então Ló escolheu para si toda a planície do Jordão, e partiu Ló para o oriente; e assim se separaram um do outro.' },
    { v: 12, en: 'Abram dwelled in the land of Canaan, and Lot dwelled in the cities of the plain, and pitched his tent toward Sodom.', pt: 'Abrão habitou na terra de Canaã, e Ló habitou nas cidades da planície e armou a sua tenda até Sodoma.' },
    { v: 13, en: 'But the men of Sodom were wicked and sinners before the LORD exceedingly.', pt: 'Ora, os homens de Sodoma eram maus e grandes pecadores diante do Senhor.' },
    { v: 14, en: 'And the LORD said unto Abram, after that Lot was separated from him, Lift up now thine eyes, and look from the place where thou art northward, and southward, and eastward, and westward.', pt: 'E disse o Senhor a Abrão, depois que Ló se separou dele: Levanta agora os teus olhos, e olha desde o lugar onde estás para o norte, e para o sul, e para o oriente, e para o ocidente.' },
    { v: 15, en: 'For all the land which thou seest, to thee will I give it, and to thy seed for ever.', pt: 'Porque toda a terra que vês te darei a ti e à tua descendência, para sempre.' },
    { v: 16, en: 'And I will make thy seed as the dust of the earth: so that if a man can number the dust of the earth, then shall thy seed also be numbered.', pt: 'E farei a tua descendência como o pó da terra; de modo que, se alguém puder contar o pó da terra, também a tua descendência será contada.' },
    { v: 17, en: 'Arise, walk through the land in the length of it and in the breadth of it; for I will give it unto thee.', pt: 'Levanta-te, percorre a terra no seu comprimento e na sua largura, porque a ti a darei.' },
    { v: 18, en: 'Then Abram removed his tent, and came and dwelt in the plain of Mamre, which is in Hebron, and built there an altar unto the LORD.', pt: 'E armou Abrão a sua tenda, e veio e habitou nos carvalhais de Manre, que estão em Hebrom; e edificou ali um altar ao Senhor.' },
  ],
  14: [
    { v: 1, en: 'And it came to pass in the days of Amraphel king of Shinar, Arioch king of Ellasar, Chedorlaomer king of Elam, and Tidal king of nations.', pt: 'E aconteceu nos dias de Anrafel, rei de Sinar, Arioque, rei de Elasar, Quedorlaomer, rei de Elão, e Tidal, rei das nações.' },
    { v: 2, en: 'That these made war with Bera king of Sodom, and with Birsha king of Gomorrah, Shinab king of Admah, and Shemeber king of Zeboiim, and the king of Bela, which is Zoar.', pt: 'Que fizeram guerra a Bera, rei de Sodoma, e a Birsa, rei de Gomorra, a Sinabe, rei de Admá, e a Semeber, rei de Zeboim, e ao rei de Belá, que é Zoar.' },
    { v: 3, en: 'All these were joined together in the vale of Siddim, which is the salt sea.', pt: 'Todos estes se ajuntaram no vale de Sidim, que é o Mar Salgado.' },
    { v: 4, en: 'Twelve years they served Chedorlaomer, and in the thirteenth year they rebelled.', pt: 'Doze anos serviram a Quedorlaomer, e no décimo terceiro ano se rebelaram.' },
    { v: 5, en: 'And in the fourteenth year came Chedorlaomer, and the kings that were with him, and smote the Rephaims in Ashteroth Karnaim, and the Zuzims in Ham, and the Emims in Shaveh Kiriathaim.', pt: 'E no décimo quarto ano veio Quedorlaomer e os reis que estavam com ele, e feriram os refains em Asterote-Carnáim, e os zuzins em Hã, e os emins na planície de Quiriataim.' },
    { v: 6, en: 'And the Horites in their mount Seir, unto Elparan, which is by the wilderness.', pt: 'E os horeus na sua montanha de Seir, até El-Parã, que está junto ao deserto.' },
    { v: 7, en: 'And they returned, and came to Enmishpat, which is Kadesh, and smote all the country of the Amalekites, and also the Amorites, that dwelt in Hazezontamar.', pt: 'E voltaram e vieram a En-Mispate, que é Cades, e feriram todo o território dos amalequitas, e também os amorreus que habitavam em Hazazom-Tamar.' },
    { v: 8, en: 'And there went out the king of Sodom, and the king of Gomorrah, and the king of Admah, and the king of Zeboiim, and the king of Bela (the same is Zoar;) and they joined battle with them in the vale of Siddim.', pt: 'E saiu o rei de Sodoma, e o rei de Gomorra, e o rei de Admá, e o rei de Zeboim, e o rei de Belá (que é Zoar), e ordenaram batalha contra eles no vale de Sidim.' },
    { v: 9, en: 'With Chedorlaomer the king of Elam, and with Tidal king of nations, and Amraphel king of Shinar, and Arioch king of Ellasar; four kings with five.', pt: 'Contra Quedorlaomer, rei de Elão, e Tidal, rei das nações, e Anrafel, rei de Sinar, e Arioque, rei de Elasar; quatro reis contra cinco.' },
    { v: 10, en: 'And the vale of Siddim was full of slimepits; and the kings of Sodom and Gomorrah fled, and fell there; and they that remained fled to the mountain.', pt: 'Ora, o vale de Sidim era cheio de poços de betume; e os reis de Sodoma e Gomorra fugiram e caíram ali; e os restantes fugiram para o monte.' },
    { v: 11, en: 'And they took all the goods of Sodom and Gomorrah, and all their victuals, and went their way.', pt: 'E tomaram todos os bens de Sodoma e Gomorra e todos os seus mantimentos, e foram-se.' },
    { v: 12, en: 'And they took Lot, Abram\'s brother\'s son, who dwelt in Sodom, and his goods, and departed.', pt: 'E tomaram também a Ló, filho do irmão de Abrão, que habitava em Sodoma, e os seus bens, e partiram.' },
    { v: 13, en: 'And there came one that had escaped, and told Abram the Hebrew; for he dwelt in the plain of Mamre the Amorite, brother of Eshcol, and brother of Aner: and these were confederate with Abram.', pt: 'E veio um que escapou, e anunciou a Abrão, o hebreu, que habitava nos carvalhais de Manre, o amorreu, irmão de Escol e irmão de Aner; estes eram aliados de Abrão.' },
    { v: 14, en: 'And when Abram heard that his brother was taken captive, he armed his trained servants, born in his own house, three hundred and eighteen, and pursued them unto Dan.', pt: 'E ouvindo Abrão que seu irmão fora levado cativo, armou os seus servos treinados, nascidos em sua casa, trezentos e dezoito, e os perseguiu até Dã.' },
    { v: 15, en: 'And he divided himself against them, he and his servants, by night, and smote them, and pursued them unto Hobah, which is on the left hand of Damascus.', pt: 'E dividiu-se contra eles de noite, ele e os seus servos, e feriu-os, e perseguiu-os até Hobá, que está à esquerda de Damasco.' },
    { v: 16, en: 'And he brought back all the goods, and also brought again his brother Lot, and his goods, and the women also, and the people.', pt: 'E trouxe de volta todos os bens, e também trouxe de volta a Ló, seu irmão, e os seus bens, e também as mulheres e o povo.' },
    { v: 17, en: 'And the king of Sodom went out to meet him after his return from the slaughter of Chedorlaomer, and of the kings that were with him, at the valley of Shaveh, which is the king\'s dale.', pt: 'E o rei de Sodoma saiu ao seu encontro, depois de ele voltar da derrota de Quedorlaomer e dos reis que estavam com ele, ao vale de Savé, que é o vale do Rei.' },
    { v: 18, en: 'And Melchizedek king of Salem brought forth bread and wine: and he was the priest of the most high God.', pt: 'E Melquisedeque, rei de Salém, trouxe pão e vinho; e era ele sacerdote do Deus Altíssimo.' },
    { v: 19, en: 'And he blessed him, and said, Blessed be Abram of the most high God, possessor of heaven and earth.', pt: 'E abençoou-o e disse: Bendito seja Abrão do Deus Altíssimo, possuidor dos céus e da terra.' },
    { v: 20, en: 'And blessed be the most high God, which hath delivered thine enemies into thy hand. And he gave him tithes of all.', pt: 'E bendito seja o Deus Altíssimo, que entregou os teus inimigos na tua mão. E Abrão lhe deu o dízimo de tudo.' },
    { v: 21, en: 'And the king of Sodom said unto Abram, Give me the persons, and take the goods to thyself.', pt: 'E disse o rei de Sodoma a Abrão: Dá-me as pessoas, e toma para ti os bens.' },
    { v: 22, en: 'And Abram said to the king of Sodom, I have lift up mine hand unto the LORD, the most high God, the possessor of heaven and earth.', pt: 'E disse Abrão ao rei de Sodoma: Levantei a minha mão ao Senhor, o Deus Altíssimo, o possuidor dos céus e da terra.' },
    { v: 23, en: 'That I will not take from a thread even to a shoelatchet, and that I will not take any thing that is thine, lest thou shouldest say, I have made Abram rich.', pt: 'Que não tomarei de um fio até a uma correia de sapato, nem nada que seja teu, para que não digas: Eu enriqueci Abrão.' },
    { v: 24, en: 'Save only that which the young men have eaten, and the portion of the men which went with me, Aner, Eshcol, and Mamre; let them take their portion.', pt: 'Exceto somente o que os jovens comeram, e a parte dos homens que foram comigo, Aner, Escol e Manre; eles tomem a sua parte.' },
  ],
  15: [
    { v: 1, en: 'After these things the word of the LORD came unto Abram in a vision, saying, Fear not, Abram: I am thy shield, and thy exceeding great reward.', pt: 'Depois destas coisas, veio a palavra do Senhor a Abrão em visão, dizendo: Não temas, Abrão; eu sou o teu escudo, e o teu galardão será muito grande.' },
    { v: 2, en: 'And Abram said, Lord GOD, what wilt thou give me, seeing I go childless, and the steward of my house is this Eliezer of Damascus?', pt: 'E disse Abrão: Senhor Deus, que me darás, visto que ando sem filhos, e o mordomo da minha casa é este Eliezer de Damasco?' },
    { v: 3, en: 'And Abram said, Behold, to me thou hast given no seed: and, lo, one born in my house is mine heir.', pt: 'Disse mais Abrão: Eis que não me deste descendência, e eis que um escravo nascido em minha casa será o meu herdeiro.' },
    { v: 4, en: 'And, behold, the word of the LORD came unto him, saying, This shall not be thine heir; but he that shall come forth out of thine own bowels shall be thine heir.', pt: 'E logo a palavra do Senhor veio a ele, dizendo: Este não será o teu herdeiro; mas o que sair das tuas próprias entranhas, esse será o teu herdeiro.' },
    { v: 5, en: 'And he brought him forth abroad, and said, Look now toward heaven, and tell the stars, if thou be able to number them: and he said unto him, So shall thy seed be.', pt: 'E trouxe-o para fora, e disse: Olha agora para os céus, e conta as estrelas, se as podes contar. E disse-lhe: Assim será a tua descendência.' },
    { v: 6, en: 'And he believed in the LORD; and he counted it to him for righteousness.', pt: 'E creu ele no Senhor, e isso lhe foi imputado por justiça.' },
    { v: 7, en: 'And he said unto him, I am the LORD that brought thee out of Ur of the Chaldees, to give thee this land to inherit it.', pt: 'E disse-lhe: Eu sou o Senhor que te tirei de Ur dos caldeus, para dar-te esta terra em herança.' },
    { v: 8, en: 'And he said, Lord GOD, whereby shall I know that I shall inherit it?', pt: 'E disse: Senhor Deus, como saberei que a hei de herdar?' },
    { v: 9, en: 'And he said unto him, Take me an heifer of three years old, and a she goat of three years old, and a ram of three years old, and a turtledove, and a young pigeon.', pt: 'E disse-lhe: Toma-me uma bezerra de três anos, e uma cabra de três anos, e um carneiro de três anos, e uma rola, e um pombinho.' },
    { v: 10, en: 'And he took unto him all these, and divided them in the midst, and laid each piece one against another: but the birds divided he not.', pt: 'E tomou tudo isso, e os partiu pelo meio, e pôs cada metade defronte da outra; mas as aves não partiu.' },
    { v: 11, en: 'And when the fowls came down upon the carcases, Abram drove them away.', pt: 'E as aves desceram sobre os cadáveres, mas Abrão as espantou.' },
    { v: 12, en: 'And when the sun was going down, a deep sleep fell upon Abram; and, lo, an horror of great darkness fell upon him.', pt: 'E ao pôr do sol caiu profundo sono sobre Abrão; e eis que um terror de grande escuridão caiu sobre ele.' },
    { v: 13, en: 'And he said unto Abram, Know of a surety that thy seed shall be a stranger in a land that is not theirs, and shall serve them; and they shall afflict them four hundred years.', pt: 'E disse a Abrão: Sabe com certeza que a tua descendência será peregrina em terra alheia, e os servirá, e eles a afligirão quatrocentos anos.' },
    { v: 14, en: 'And also that nation, whom they shall serve, will I judge: and afterward shall they come out with great substance.', pt: 'Mas eu também julgarei a nação a qual servirem; e depois sairão com grande riqueza.' },
    { v: 15, en: 'And thou shalt go to thy fathers in peace; thou shalt be buried in a good old age.', pt: 'E tu irás a teus pais em paz; serás sepultado em boa velhice.' },
    { v: 16, en: 'But in the fourth generation they shall come hither again: for the iniquity of the Amorites is not yet full.', pt: 'Mas na quarta geração voltarão aqui, porque a iniquidade dos amorreus ainda não está completa.' },
    { v: 17, en: 'And it came to pass, that, when the sun went down, and it was dark, behold a smoking furnace, and a burning lamp that passed between those pieces.', pt: 'E aconteceu que, ao pôr do sol, houve escuridão; e eis um forno fumegante e uma tocha de fogo que passou entre aqueles pedaços.' },
    { v: 18, en: 'In the same day the LORD made a covenant with Abram, saying, Unto thy seed have I given this land, from the river of Egypt unto the great river, the river Euphrates.', pt: 'Naquele mesmo dia fez o Senhor uma aliança com Abrão, dizendo: À tua descendência dei esta terra, desde o rio do Egito até ao grande rio Eufrates.' },
    { v: 19, en: 'The Kenites, and the Kenizzites, and the Kadmonites.', pt: 'Os queneus, e os quenezeus, e os cadmoneus.' },
    { v: 20, en: 'And the Hittites, and the Perizzites, and the Rephaims.', pt: 'E os heteus, e os ferezeus, e os refains.' },
    { v: 21, en: 'And the Amorites, and the Canaanites, and the Girgashites, and the Jebusites.', pt: 'E os amorreus, e os cananeus, e os girgaseus, e os jebuseus.' },
  ],
  16: [
    { v: 1, en: 'Now Sarai Abram\'s wife bare him no children: and she had an handmaid, an Egyptian, whose name was Hagar.', pt: 'Ora, Sarai, mulher de Abrão, não lhe dava filhos; e ela tinha uma serva egípcia cujo nome era Agar.' },
    { v: 2, en: 'And Sarai said unto Abram, Behold now, the LORD hath restrained me from bearing: I pray thee, go in unto my maid; it may be that I may obtain children by her. And Abram hearkened to the voice of Sarai.', pt: 'E disse Sarai a Abrão: Eis que o Senhor me impediu de dar à luz; peço-te que te chegues à minha serva; talvez que por ela eu seja edificada. E Abrão atendeu à voz de Sarai.' },
    { v: 3, en: 'And Sarai Abram\'s wife took Hagar her maid the Egyptian, after Abram had dwelt ten years in the land of Canaan, and gave her to her husband Abram to be his wife.', pt: 'E Sarai, mulher de Abrão, tomou Agar, a egípcia, sua serva, ao fim de dez anos que Abrão habitara na terra de Canaã, e a deu por mulher a Abrão, seu marido.' },
    { v: 4, en: 'And he went in unto Hagar, and she conceived: and when she saw that she had conceived, her mistress was despised in her eyes.', pt: 'E ele se chegou a Agar, e ela concebeu; e quando viu que havia concebido, sua senhora se tornou vil aos seus olhos.' },
    { v: 5, en: 'And Sarai said unto Abram, My wrong be upon thee: I have given my maid into thy bosom; and when she saw that she had conceived, I was despised in her eyes: the LORD judge between me and thee.', pt: 'Então disse Sarai a Abrão: A minha injúria vem de ti; eu mesma te dei a minha serva ao seio, e ela, vendo que havia concebido, fez-me vil aos seus olhos; o Senhor julgue entre mim e ti.' },
    { v: 6, en: 'But Abram said unto Sarai, Behold, thy maid is in thy hand; do to her as it pleaseth thee. And when Sarai dealt hardly with her, she fled from her face.', pt: 'E disse Abrão a Sarai: Eis que a tua serva está na tua mão; faze com ela o que bom te parecer. E Sarai a humilhou; e ela fugiu da sua presença.' },
    { v: 7, en: 'And the angel of the LORD found her by a fountain of water in the wilderness, by the fountain in the way to Shur.', pt: 'E o anjo do Senhor a achou junto a uma fonte de água no deserto, junto à fonte no caminho de Sur.' },
    { v: 8, en: 'And he said, Hagar, Sarai\'s maid, whence camest thou? and whither wilt thou go? And she said, I flee from the face of my mistress Sarai.', pt: 'E disse: Agar, serva de Sarai, donde vens, e para onde vais? E ela disse: Fujo da presença de Sarai, minha senhora.' },
    { v: 9, en: 'And the angel of the LORD said unto her, Return to thy mistress, and submit thyself under her hands.', pt: 'E disse-lhe o anjo do Senhor: Volta para a tua senhora, e submete-te sob as suas mãos.' },
    { v: 10, en: 'And the angel of the LORD said unto her, I will multiply thy seed exceedingly, that it shall not be numbered for multitude.', pt: 'Disse-lhe mais o anjo do Senhor: Multiplicarei a tua descendência em grande maneira, que por multidão não poderá ser contada.' },
    { v: 11, en: 'And the angel of the LORD said unto her, Behold, thou art with child, and shalt bear a son, and shalt call his name Ishmael; because the LORD hath heard thy affliction.', pt: 'Disse-lhe mais o anjo do Senhor: Eis que estás grávida, e darás à luz um filho, e chamá-lo-ás Ismael, porque o Senhor atendeu à tua aflição.' },
    { v: 12, en: 'And he will be a wild man; his hand will be against every man, and every man\'s hand against him; and he shall dwell in the presence of all his brethren.', pt: 'E ele será homem feroz; a sua mão será contra todos, e a mão de todos contra ele; e habitará em frente de todos os seus irmãos.' },
    { v: 13, en: 'And she called the name of the LORD that spake unto her, Thou God seest me: for she said, Have I also here looked after him that seeth me?', pt: 'E ela chamou o nome do Senhor que lhe falava: Tu és o Deus que me vê; porque disse: Porventura vi eu aqui o que me vê?' },
    { v: 14, en: 'Wherefore the well was called Beerlahairoi; behold, it is between Kadesh and Bered.', pt: 'Por isso chamou ao poço: O poço do Vivente que me vê; eis que está entre Cades e Berede.' },
    { v: 15, en: 'And Hagar bare Abram a son: and Abram called his son\'s name, which Hagar bare, Ishmael.', pt: 'E Agar deu um filho a Abrão; e Abrão chamou o nome do filho que Agar lhe deu, Ismael.' },
    { v: 16, en: 'And Abram was fourscore and six years old, when Hagar bare Ishmael to Abram.', pt: 'E Abrão tinha oitenta e seis anos quando Agar lhe deu à luz Ismael.' },
  ],
  17: [
    { v: 1, en: 'And when Abram was ninety years old and nine, the LORD appeared to Abram, and said unto him, I am the Almighty God; walk before me, and be thou perfect.', pt: 'E sendo Abrão da idade de noventa e nove anos, apareceu o Senhor a Abrão e disse-lhe: Eu sou o Deus Todo-poderoso; anda perante mim e sê perfeito.' },
    { v: 2, en: 'And I will make my covenant between me and thee, and will multiply thee exceedingly.', pt: 'E porei a minha aliança entre mim e ti, e te multiplicarei em grande maneira.' },
    { v: 3, en: 'And Abram fell on his face: and God talked with him, saying.', pt: 'E Abrão prostrou-se sobre o seu rosto; e Deus lhe falou, dizendo:' },
    { v: 4, en: 'As for me, behold, my covenant is with thee, and thou shalt be a father of many nations.', pt: 'Quanto a mim, eis a minha aliança contigo: serás pai de muitas nações.' },
    { v: 5, en: 'Neither shall thy name any more be called Abram, but thy name shall be Abraham; for a father of many nations have I made thee.', pt: 'E nunca mais te chamarás Abrão; mas o teu nome será Abraão; porque eu te farei pai de muitas nações.' },
    { v: 6, en: 'And I will make thee exceeding fruitful, and I will make nations of thee, and kings shall come out of thee.', pt: 'E far-te-ei frutificar em grande maneira, e de ti farei nações, e reis procederão de ti.' },
    { v: 7, en: 'And I will establish my covenant between me and thee and thy seed after thee in their generations for an everlasting covenant, to be a God unto thee, and to thy seed after thee.', pt: 'E estabelecerei a minha aliança entre mim e ti e a tua descendência depois de ti nas suas gerações, por aliança perpétua, para ser o teu Deus e o da tua descendência depois de ti.' },
    { v: 8, en: 'And I will give unto thee, and to thy seed after thee, the land wherein thou art a stranger, all the land of Canaan, for an everlasting possession; and I will be their God.', pt: 'E dar-te-ei a ti, e à tua descendência depois de ti, a terra das tuas peregrinações, toda a terra de Canaã, em possessão perpétua; e eu serei o seu Deus.' },
    { v: 9, en: 'And God said unto Abraham, Thou shalt keep my covenant therefore, thou, and thy seed after thee in their generations.', pt: 'E disse Deus a Abraão: Tu, porém, guardarás a minha aliança, tu e a tua descendência depois de ti nas suas gerações.' },
    { v: 10, en: 'This is my covenant, which ye shall keep, between me and you and thy seed after thee; Every man child among you shall be circumcised.', pt: 'Esta é a minha aliança, que guardareis entre mim e vós, e a tua descendência depois de ti: todo o macho entre vós será circuncidado.' },
    { v: 11, en: 'And ye shall circumcise the flesh of your foreskin; and it shall be a token of the covenant betwixt me and you.', pt: 'E circuncidareis a carne do vosso prepúcio; e isso será por sinal da aliança entre mim e vós.' },
    { v: 12, en: 'And he that is eight days old shall be circumcised among you, every man child in your generations, he that is born in the house, or bought with money of any stranger, which is not of thy seed.', pt: 'E o filho de oito dias será circuncidado entre vós, todo o macho nas vossas gerações, tanto o nascido em casa como o comprado por dinheiro a qualquer estrangeiro que não for da tua descendência.' },
    { v: 13, en: 'He that is born in thy house, and he that is bought with thy money, must needs be circumcised: and my covenant shall be in your flesh for an everlasting covenant.', pt: 'Certamente o nascido em tua casa e o comprado por teu dinheiro serão circuncidados; e a minha aliança estará na vossa carne por aliança perpétua.' },
    { v: 14, en: 'And the uncircumcised man child whose flesh of his foreskin is not circumcised, that soul shall be cut off from his people; he hath broken my covenant.', pt: 'E o macho que não for circuncidado na carne do prepúcio, essa alma será extirpada do seu povo; quebrou a minha aliança.' },
    { v: 15, en: 'And God said unto Abraham, As for Sarai thy wife, thou shalt not call her name Sarai, but Sarah shall her name be.', pt: 'Disse mais Deus a Abraão: Quanto a Sarai, tua mulher, não lhe chamarás mais Sarai, mas Sara será o seu nome.' },
    { v: 16, en: 'And I will bless her, and give thee a son also of her: yea, I will bless her, and she shall be a mother of nations; kings of people shall be of her.', pt: 'E eu a abençoarei, e também te darei dela um filho; e eu a abençoarei, e ela será mãe de nações; reis de povos procederam dela.' },
    { v: 17, en: 'Then Abraham fell upon his face, and laughed, and said in his heart, Shall a child be born unto him that is an hundred years old? and shall Sarah, that is ninety years old, bear?', pt: 'Então Abraão se prostrou sobre o seu rosto e riu-se, e disse no seu coração: A um homem de cem anos nascerá um filho? E Sara, de noventa anos, dará à luz?' },
    { v: 18, en: 'And Abraham said unto God, O that Ishmael might live before thee!', pt: 'E disse Abraão a Deus: Tomara que Ismael vivesse diante de ti!' },
    { v: 19, en: 'And God said, Sarah thy wife shall bear thee a son indeed; and thou shalt call his name Isaac: and I will establish my covenant with him for an everlasting covenant, and with his seed after him.', pt: 'E disse Deus: Na verdade Sara, tua mulher, te dará um filho, e chamá-lo-ás Isaque; e estabelecerei a minha aliança com ele por aliança perpétua, e com a sua descendência depois dele.' },
    { v: 20, en: 'And as for Ishmael, I have heard thee: Behold, I have blessed him, and will make him fruitful, and will multiply him exceedingly; twelve princes shall he beget, and I will make him a great nation.', pt: 'E quanto a Ismael, ouvi-te; eis que o abençoarei, e o farei frutificar, e o multiplicarei em grande maneira; doze príncipes gerará, e o farei uma grande nação.' },
    { v: 21, en: 'But my covenant will I establish with Isaac, which Sarah shall bear unto thee at this set time in the next year.', pt: 'Mas a minha aliança estabelecerei com Isaque, que Sara te dará à luz a este tempo determinado no ano seguinte.' },
    { v: 22, en: 'And he left off talking with him, and God went up from Abraham.', pt: 'E acabou de falar com ele, e subiu Deus de junto de Abraão.' },
    { v: 23, en: 'And Abraham took Ishmael his son, and all that were born in his house, and all that were bought with his money, every male among the men of Abraham\'s house; and circumcised the flesh of their foreskin in the selfsame day, as God had said unto him.', pt: 'Então Abraão tomou a Ismael, seu filho, e a todos os nascidos em sua casa, e a todos os comprados por seu dinheiro, a todo o macho dos homens da casa de Abraão, e circuncidou a carne do prepúcio deles naquele mesmo dia, como Deus lhe dissera.' },
    { v: 24, en: 'And Abraham was ninety years old and nine, when he was circumcised in the flesh of his foreskin.', pt: 'E Abraão tinha noventa e nove anos quando foi circuncidado na carne do seu prepúcio.' },
    { v: 25, en: 'And Ishmael his son was thirteen years old, when he was circumcised in the flesh of his foreskin.', pt: 'E Ismael, seu filho, tinha treze anos quando foi circuncidado na carne do seu prepúcio.' },
    { v: 26, en: 'In the selfsame day was Abraham circumcised, and Ishmael his son.', pt: 'Naquele mesmo dia foram circuncidados Abraão e Ismael, seu filho.' },
    { v: 27, en: 'And all the men of his house, born in the house, and bought with money of the stranger, were circumcised with him.', pt: 'E todos os homens da sua casa, tanto os nascidos em casa como os comprados por dinheiro a estrangeiros, foram circuncidados com ele.' },
  ],
  18: [
    { v: 1, en: 'And the LORD appeared unto him in the plains of Mamre: and he sat in the tent door in the heat of the day.', pt: 'E o Senhor apareceu a ele nos carvalhais de Manre, e ele estava assentado à porta da tenda no calor do dia.' },
    { v: 2, en: 'And he lift up his eyes and looked, and, lo, three men stood by him: and when he saw them, he ran to meet them from the tent door, and bowed himself toward the ground.', pt: 'E levantou os seus olhos, e olhou, e eis que três homens estavam em pé junto a ele; e quando os viu, correu da porta da tenda a encontrá-los, e se prostrou em terra.' },
    { v: 3, en: 'And said, My Lord, if now I have found favour in thy sight, pass not away, I pray thee, from thy servant.', pt: 'E disse: Senhor, se agora achei graça aos teus olhos, não passes, peço-te, por teu servo.' },
    { v: 4, en: 'Let a little water, I pray you, be fetched, and wash your feet, and rest yourselves under the tree.', pt: 'Que se traga um pouco de água, e lavai os vossos pés, e recostai-vos debaixo da árvore.' },
    { v: 5, en: 'And I will fetch a morsel of bread, and comfort ye your hearts; after that ye shall pass on: for therefore are ye come to your servant. And they said, So do, as thou hast said.', pt: 'E trarei um bocado de pão, e confortai o vosso coração; depois passareis adiante; porque para isso passastes junto ao vosso servo. E disseram: Faze assim como disseste.' },
    { v: 6, en: 'And Abraham hastened into the tent unto Sarah, and said, Make ready quickly three measures of fine meal, knead it, and make cakes upon the hearth.', pt: 'E Abraão se apressou para a tenda, a Sara, e disse: Apressa-te, amassa três medidas de farinha fina, e faze bolos.' },
    { v: 7, en: 'And Abraham ran unto the herd, and fetch a calf tender and good, and gave it unto a young man; and he hasted to dress it.', pt: 'E Abraão correu ao gado, e tomou um bezerro tenro e bom, e o deu ao moço, que se apressou a prepará-lo.' },
    { v: 8, en: 'And he took butter, and milk, and the calf which he had dressed, and set it before them; and he stood by them under the tree, and they did eat.', pt: 'E tomou manteiga e leite, e o bezerro que havia preparado, e pôs tudo diante deles; e ele estava em pé junto a eles debaixo da árvore; e eles comeram.' },
    { v: 9, en: 'And they said unto him, Where is Sarah thy wife? And he said, Behold, in the tent.', pt: 'E disseram-lhe: Onde está Sara, tua mulher? E ele disse: Eis que está na tenda.' },
    { v: 10, en: 'And he said, I will certainly return unto thee according to the time of life; and, lo, Sarah thy wife shall have a son. And Sarah heard it in the tent door, which was behind him.', pt: 'E disse: Certamente voltarei a ti segundo o tempo da vida; e eis que Sara, tua mulher, terá um filho. E Sara estava ouvindo à porta da tenda, que estava atrás dele.' },
    { v: 11, en: 'Now Abraham and Sarah were old and well stricken in age; and it ceased to be with Sarah after the manner of women.', pt: 'E Abraão e Sara eram velhos e avançados em dias; havia cessado em Sara o que é costume das mulheres.' },
    { v: 12, en: 'Therefore Sarah laughed within herself, saying, After I am waxed old shall I have pleasure, my lord being old also?', pt: 'Portanto Sara riu entre si, dizendo: Depois de envelhecida terei prazer, sendo também meu senhor velho?' },
    { v: 13, en: 'And the LORD said unto Abraham, Wherefore did Sarah laugh, saying, Shall I of a surety bear a child, which am old?', pt: 'E disse o Senhor a Abraão: Por que se riu Sara, dizendo: Parirá com certeza uma velha como eu?' },
    { v: 14, en: 'Is any thing too hard for the LORD? At the time appointed I will return unto thee, according to the time of life, and Sarah shall have a son.', pt: 'Haverá coisa alguma difícil demais para o Senhor? No tempo determinado voltarei a ti, segundo o tempo da vida, e Sara terá um filho.' },
    { v: 15, en: 'Then Sarah denied, saying, I laughed not; for she was afraid. And he said, Nay; but thou didst laugh.', pt: 'Então Sara negou, dizendo: Não me ri; porque teve medo. E ele disse: Não, mas te riste.' },
    { v: 16, en: 'And the men rose up from thence, and looked toward Sodom: and Abraham went with them to bring them on the way.', pt: 'E levantaram-se os homens dali, e olharam para Sodoma; e Abraão ia com eles para os acompanhar.' },
    { v: 17, en: 'And the LORD said, Shall I hide from Abraham that thing which I do.', pt: 'E disse o Senhor: Encobrirei eu de Abraão o que estou para fazer?' },
    { v: 18, en: 'Seeing that Abraham shall surely become a great and mighty nation, and all the nations of the earth shall be blessed in him?', pt: 'Visto que Abraão certamente se tornará uma nação grande e poderosa, e nele serão benditas todas as nações da terra?' },
    { v: 19, en: 'For I know him, that he will command his children and his household after him, and they shall keep the way of the LORD, to do justice and judgment; that the LORD may bring upon Abraham that which he hath spoken of him.', pt: 'Porque eu o conheço, e sei que há de ordenar a seus filhos e à sua família depois de si, que guardem o caminho do Senhor, praticando a justiça e o juízo; para que o Senhor faça vir sobre Abraão o que falou acerca dele.' },
    { v: 20, en: 'And the LORD said, Because the cry of Sodom and Gomorrah is great, and because their sin is very grievous.', pt: 'E disse o Senhor: O clamor de Sodoma e Gomorra é grande, e o seu pecado é mui grave.' },
    { v: 21, en: 'I will go down now, and see whether they have done altogether according to the cry of it, which is come unto me; and if not, I will know.', pt: 'Descerei agora, e verei se procedem de todo de acordo com o clamor que tem chegado até mim; e se não, sabê-lo-ei.' },
    { v: 22, en: 'And the men turned their faces from thence, and went toward Sodom: but Abraham stood yet before the LORD.', pt: 'E os homens partiram dali e foram em direção a Sodoma; mas Abraão ainda estava em pé perante o Senhor.' },
    { v: 23, en: 'And Abraham drew near, and said, Wilt thou also destroy the righteous with the wicked?', pt: 'E Abraão se aproximou e disse: Destruirás também o justo com o ímpio?' },
    { v: 24, en: 'Peradventure there be fifty righteous within the city: wilt thou also destroy and not spare the place for the fifty righteous that are therein?', pt: 'Se houver cinquenta justos dentro da cidade, os destruirás também, e não perdoarás o lugar por causa dos cinquenta justos que estão nela?' },
    { v: 25, en: 'That be far from thee to do after this manner, to slay the righteous with the wicked: and that the righteous should be as the wicked, that be far from thee: Shall not the Judge of all the earth do right?', pt: 'Longe de ti fazer tal coisa, matar o justo com o ímpio; e que o justo seja como o ímpio, longe de ti; o Juiz de toda a terra não fará o que é justo?' },
    { v: 26, en: 'And the LORD said, If I find in Sodom fifty righteous within the city, then I will spare all the place for their sakes.', pt: 'E disse o Senhor: Se eu achar em Sodoma cinquenta justos dentro da cidade, perdoarei todo o lugar por causa deles.' },
    { v: 27, en: 'And Abraham answered and said, Behold now, I have taken upon me to speak unto the Lord, which am but dust and ashes.', pt: 'E respondeu Abraão e disse: Eis que me atrevi a falar ao Senhor, eu que sou pó e cinza.' },
    { v: 28, en: 'Peradventure there shall lack five of the fifty righteous: wilt thou destroy all the city for lack of five? And he said, If I find there forty and five, I will not destroy it.', pt: 'Porventura faltarão cinco dos cinquenta justos; destruirás toda a cidade por falta de cinco? E disse: Se eu achar ali quarenta e cinco, não a destruirei.' },
    { v: 29, en: 'And he spake unto him yet again, and said, Peradventure there shall be forty found there. And he said, I will not do it for forty\'s sake.', pt: 'E tornou a falar-lhe, e disse: Porventura se acharão ali quarenta. E disse: Por amor dos quarenta não o farei.' },
    { v: 30, en: 'And he said unto him, Oh let not the Lord be angry, and I will speak: Peradventure there shall thirty be found there. And he said, I will not do it, if I find thirty there.', pt: 'E disse: Ora, não se ire o Senhor, e eu falarei; porventura se acharão ali trinta. E disse: Não o farei se achar ali trinta.' },
    { v: 31, en: 'And he said, Behold now, I have taken upon me to speak unto the Lord: Peradventure there shall be twenty found there. And he said, I will not destroy it for twenty\'s sake.', pt: 'E disse: Eis que me atrevi a falar ao Senhor; porventura se acharão ali vinte. E disse: Não a destruirei por amor dos vinte.' },
    { v: 32, en: 'And he said, Oh let not the Lord be angry, and I will speak yet but this once: Peradventure ten shall be found there. And he said, I will not destroy it for ten\'s sake.', pt: 'E disse: Ora, não se ire o Senhor, e falarei somente desta vez; porventura se acharão ali dez. E disse: Não a destruirei por amor dos dez.' },
    { v: 33, en: 'And the LORD went his way, as soon as he had left communing with Abraham: and Abraham returned unto his place.', pt: 'E o Senhor foi-se logo que acabou de falar com Abraão; e Abraão voltou para o seu lugar.' },
  ],
  19: [
    { v: 1, en: 'And there came two angels to Sodom at even; and Lot sat in the gate of Sodom: and Lot seeing them rose up to meet them; and he bowed himself with his face toward the ground.', pt: 'E chegaram dois anjos a Sodoma à tarde; e Ló estava assentado à porta de Sodoma; e vendo-os Ló levantou-se a encontrá-los, e se inclinou com o rosto em terra.' },
    { v: 2, en: 'And he said, Behold now, my lords, turn in, I pray you, into your servant\'s house, and tarry all night, and wash your feet, and ye shall rise up early, and go on your ways. And they said, Nay; but we will abide in the street all night.', pt: 'E disse: Eis aqui, meus senhores, entrai, peço-vos, em casa de vosso servo, e ficai a noite, e lavai os vossos pés; e de manhã cedo vos levantareis e seguireis o vosso caminho. E disseram: Não, que ficaremos nesta praça a noite.' },
    { v: 3, en: 'And he pressed upon them greatly; and they turned in unto him, and entered into his house; and he made them a feast, and did bake unleavened bread, and they did eat.', pt: 'E ele os importunou muito; e eles se voltaram para ele, e entraram em sua casa; e ele lhes fez um banquete, e assou pães ázimos, e eles comeram.' },
    { v: 4, en: 'But before they lay down, the men of the city, even the men of Sodom, compassed the house round, both old and young, all the people from every quarter.', pt: 'Antes que se deitassem, os homens daquela cidade, os homens de Sodoma, cercaram a casa, tanto os moços como os velhos, todo o povo de todos os cantos.' },
    { v: 5, en: 'And they called unto Lot, and said unto him, Where are the men which came in to thee this night? bring them out unto us, that we may know them.', pt: 'E chamaram a Ló, e disseram-lhe: Onde estão os homens que vieram a ti esta noite? Traze-os a nós, para que os conheçamos.' },
    { v: 6, en: 'And Lot went out at the door unto them, and shut the door after him.', pt: 'E saiu Ló a eles à porta, e fechou a porta após si.' },
    { v: 7, en: 'And said, I pray you, brethren, do not so wickedly.', pt: 'E disse: Rogo-vos, irmãos, que não procedais tão malvadamente.' },
    { v: 8, en: 'Behold now, I have two daughters which have not known man; let me, I pray you, bring them out unto you, and do ye to them as is good in your eyes: only unto these men do nothing; for therefore came they under the shadow of my roof.', pt: 'Eis que tenho duas filhas que nunca conheceram varão; deixai-me, peço-vos, trazê-las a vós, e fazei-lhes o que bem vos parecer; somente a estes homens nada façais, porque vieram à sombra do meu teto.' },
    { v: 9, en: 'And they said, Stand back. And they said again, This one fellow came in to sojourn, and he will needs be a judge: now will we deal worse with thee, than with them. And they pressed sore upon the man, even Lot, and came near to break the door.', pt: 'E disseram: Afasta-te daí. E disseram mais: Este veio para viver aqui como forasteiro, e quer ser o nosso juiz? Agora te faremos mais mal do que a eles. E empurravam muito ao homem, a Ló, e se chegavam para arrombar a porta.' },
    { v: 10, en: 'But the men put forth their hand, and pulled Lot into the house to them, and shut to the door.', pt: 'Então os homens estenderam a mão e fizeram entrar Ló junto a eles na casa, e fecharam a porta.' },
    { v: 11, en: 'And they smote the men that were at the door of the house with blindness, both small and great: so that they wearied themselves to find the door.', pt: 'E feriram com cegueira os homens que estavam à porta da casa, desde o menor até ao maior, de modo que se cansaram procurando a porta.' },
    { v: 12, en: 'And the men said unto Lot, Hast thou here any besides? son in law, and thy sons, and thy daughters, and whatsoever thou hast in the city, bring them out of this place.', pt: 'E disseram os homens a Ló: Tens aqui mais alguém? genros, e teus filhos, e tuas filhas, e tudo o que tens na cidade, tira-os deste lugar.' },
    { v: 13, en: 'For we will destroy this place, because the cry of them is waxen great before the face of the LORD; and the LORD hath sent us to destroy it.', pt: 'Porque vamos destruir este lugar, pois o seu clamor cresceu perante o Senhor; e o Senhor nos enviou para o destruir.' },
    { v: 14, en: 'And Lot went out, and spake unto his sons in law, which married his daughters, and said, Up, get you out of this place; for the LORD will destroy this city. But he seemed as one that mocked unto his sons in law.', pt: 'E saiu Ló, e falou aos seus genros, que haviam de casar com suas filhas, e disse: Levantai-vos, saí deste lugar; porque o Senhor vai destruir esta cidade. Mas pareceu aos seus genros que ele estava gracejando.' },
    { v: 15, en: 'And when the morning arose, then the angels hastened Lot, saying, Arise, take thy wife, and thy two daughters, which are here; lest thou be consumed in the iniquity of the city.', pt: 'E quando a alva raiou, os anjos instaram com Ló, dizendo: Levanta-te, toma a tua mulher e as tuas duas filhas que se acham aqui, para que não pereças na iniquidade da cidade.' },
    { v: 16, en: 'And while he lingered, the men laid hold upon his hand, and upon the hand of his wife, and upon the hand of his two daughters; the LORD being merciful unto him: and they brought him forth, and set him without the city.', pt: 'E como se tardasse, pegaram os homens na sua mão, e na mão de sua mulher, e na mão de suas duas filhas, sendo o Senhor misericordioso para com ele; e o tiraram e o puseram fora da cidade.' },
    { v: 17, en: 'And it came to pass, when they had brought them forth abroad, that he said, Escape for thy life; look not behind thee, neither stay thou in all the plain; escape to the mountain, lest thou be consumed.', pt: 'E aconteceu que, quando os tiraram para fora, disse um deles: Salva a tua vida; não olhes para trás, nem te demores em toda esta planície; foge para o monte, para que não pereças.' },
    { v: 18, en: 'And Lot said unto them, Oh, not so, my Lord.', pt: 'E disse Ló: Não, meu Senhor, peço-te.' },
    { v: 19, en: 'Behold now, thy servant hath found grace in thy sight, and thou hast magnified thy mercy, which thou hast shewed unto me in saving my life; and I cannot escape to the mountain, lest some evil take me, and I die.', pt: 'Eis que o teu servo achou graça aos teus olhos, e engrandeceste a tua misericórdia que me fizeste, em conservar-me a vida; mas eu não posso escapar para o monte, para que não me sobrevenha algum mal, e eu morra.' },
    { v: 20, en: 'Behold now, this city is near to flee unto, and it is a little one: Oh, let me escape thither, (is it not a little one?) and my soul shall live.', pt: 'Eis que esta cidade está perto para fugir para lá, e ela é pequena; deixa-me escapar para lá (não é ela pequena?), e a minha alma viverá.' },
    { v: 21, en: 'And he said unto him, See, I have accepted thee concerning this thing also, that I will not overthrow this city, for the which thou hast spoken.', pt: 'E disse-lhe: Eis que atendi a ti também neste pedido, de não destruir a cidade da qual falaste.' },
    { v: 22, en: 'Haste thee, escape thither; for I cannot do any thing till thou be come thither. Therefore the name of the city was called Zoar.', pt: 'Apressa-te, escapa para lá; porque nada posso fazer até que tenhas chegado lá. Por isso chamou o nome daquela cidade Zoar.' },
    { v: 23, en: 'The sun was risen upon the earth when Lot entered into Zoar.', pt: 'O sol saía sobre a terra quando Ló entrou em Zoar.' },
    { v: 24, en: 'Then the LORD rained upon Sodom and upon Gomorrah brimstone and fire from the LORD out of heaven.', pt: 'Então o Senhor fez chover enxofre e fogo sobre Sodoma e sobre Gomorra, da parte do Senhor dos céus.' },
    { v: 25, en: 'And he overthrew those cities, and all the plain, and all the inhabitants of the cities, and that which grew upon the ground.', pt: 'E destruiu aquelas cidades e toda aquela planície, e todos os habitantes daquelas cidades, e o que nascia da terra.' },
    { v: 26, en: 'But his wife looked back from behind him, and she became a pillar of salt.', pt: 'E a mulher de Ló olhou para trás, e se tornou uma estátua de sal.' },
    { v: 27, en: 'And Abraham gat up early in the morning to the place where he stood before the LORD.', pt: 'E Abraão se levantou de madrugada, ao lugar onde estivera perante o Senhor.' },
    { v: 28, en: 'And he looked toward Sodom and Gomorrah, and toward all the land of the plain, and beheld, and, lo, the smoke of the country went up as the smoke of a furnace.', pt: 'E contemplou Sodoma e Gomorra, e toda a terra daquela planície, e viu; e eis que a fumaça da terra subia como a fumaça de uma fornalha.' },
    { v: 29, en: 'And it came to pass, when God destroyed the cities of the plain, that God remembered Abraham, and sent Lot out of the midst of the overthrow, when he overthrew the cities in the which Lot dwelt.', pt: 'E aconteceu que, quando Deus destruiu as cidades da planície, Deus se lembrou de Abraão, e tirou a Ló do meio da destruição, quando destruiu as cidades em que Ló habitava.' },
    { v: 30, en: 'And Lot went up out of Zoar, and dwelt in the mountain, and his two daughters with him; for he feared to dwell in Zoar: and he dwelt in a cave, he and his two daughters.', pt: 'E Ló subiu de Zoar, e habitou no monte, e as suas duas filhas com ele; porque teve medo de ficar em Zoar; e habitou numa caverna, ele e as suas duas filhas.' },
    { v: 31, en: 'And the firstborn said unto the younger, Our father is old, and there is not a man in the earth to come in unto us after the manner of all the earth.', pt: 'E disse a primogênita à mais nova: Nosso pai é velho, e não há homem na terra que entre a nós conforme o costume de toda a terra.' },
    { v: 32, en: 'Come, let us make our father drink wine, and we will lie with him, that we may preserve seed of our father.', pt: 'Vem, demos a beber vinho a nosso pai, e nos deitaremos com ele, para que conservemos descendência de nosso pai.' },
    { v: 33, en: 'And they made their father drink wine that night: and the firstborn went in, and lay with her father; and he perceived not when she lay down, nor when she arose.', pt: 'E deram a beber vinho a seu pai naquela noite; e foi a primogênita, e deitou-se com seu pai; e ele não o percebeu quando ela se deitou, nem quando se levantou.' },
    { v: 34, en: 'And it came to pass on the morrow, that the firstborn said unto the younger, Behold, I lay yesternight with my father: let us make him drink wine this night also; and go thou in, and lie with him, that we may preserve seed of our father.', pt: 'E no dia seguinte disse a primogênita à mais nova: Eis que me deitei ontem à noite com meu pai; demos-lhe a beber vinho também esta noite, e entra tu, e deita-te com ele, para que conservemos descendência de nosso pai.' },
    { v: 35, en: 'And they made their father drink wine that night also: and the younger arose, and lay with him; and he perceived not when she lay down, nor when she arose.', pt: 'E deram a beber vinho a seu pai também naquela noite; e levantou-se a mais nova, e deitou-se com ele; e ele não o percebeu quando ela se deitou, nem quando se levantou.' },
    { v: 36, en: 'Thus were both the daughters of Lot with child by their father.', pt: 'E assim ficaram grávidas as duas filhas de Ló por seu pai.' },
    { v: 37, en: 'And the firstborn bare a son, and called his name Moab: the same is the father of the Moabites unto this day.', pt: 'E a primogênita deu à luz um filho, e chamou o seu nome Moabe; este é o pai dos moabitas até ao dia de hoje.' },
    { v: 38, en: 'And the younger, she also bare a son, and called his name Benammi: the same is the father of the children of Ammon unto this day.', pt: 'E a mais nova também deu à luz um filho, e chamou o seu nome Ben-Ami; este é o pai dos filhos de Amom até ao dia de hoje.' },
  ],
  20: [
    { v: 1, en: 'And Abraham journeyed from thence toward the south country, and dwelled between Kadesh and Shur, and sojourned in Gerar.', pt: 'E partiu Abraão dali para o sul, e habitou entre Cades e Sur, e viveu como estrangeiro em Gerar.' },
    { v: 2, en: 'And Abraham said of Sarah his wife, She is my sister: and Abimelech king of Gerar sent, and took Sarah.', pt: 'E disse Abraão de Sara, sua mulher: Ela é minha irmã. E Abimeleque, rei de Gerar, mandou chamar Sara, e a tomou.' },
    { v: 3, en: 'But God came to Abimelech in a dream by night, and said to him, Behold, thou art but a dead man, for the woman which thou hast taken; for she is a man\'s wife.', pt: 'Mas Deus veio a Abimeleque em sonho de noite, e disse-lhe: Eis que és homem morto por causa da mulher que tomaste; porque ela é casada.' },
    { v: 4, en: 'But Abimelech had not come near her: and he said, Lord, wilt thou slay also a righteous nation?', pt: 'Mas Abimeleque não se havia chegado a ela; e disse: Senhor, matarás também a uma nação justa?' },
    { v: 5, en: 'Said he not unto me, She is my sister? and she, even she herself said, He is my brother: in the integrity of my heart and innocency of my hands have I done this.', pt: 'Não me disse ele mesmo: Ela é minha irmã? E ela também disse: Ele é meu irmão. Com sinceridade de coração e com inocência de mãos fiz isto.' },
    { v: 6, en: 'And God said unto him in a dream, Yea, I know that thou didst this in the integrity of thy heart; for I also withheld thee from sinning against me: therefore suffered I thee not to touch her.', pt: 'E disse-lhe Deus em sonho: Também eu sei que com sinceridade de coração fizeste isso; e eu mesmo te guardei de pecar contra mim; por isso não te deixei tocá-la.' },
    { v: 7, en: 'Now therefore restore the man his wife; for he is a prophet, and he shall pray for thee, and thou shalt live: and if thou restore her not, know thou that thou shalt surely die, thou, and all that are thine.', pt: 'Agora, pois, restitui a mulher a este homem, porque ele é profeta, e orará por ti, e viverás; mas se não a restituíres, sabe que certamente morrerás, tu e todos os teus.' },
    { v: 8, en: 'Therefore Abimelech rose early in the morning, and called all his servants, and told all these things in their ears: and the men were sore afraid.', pt: 'E Abimeleque se levantou de madrugada, e chamou todos os seus servos, e disse estas palavras aos seus ouvidos; e os homens tiveram muito medo.' },
    { v: 9, en: 'Then Abimelech called Abraham, and said unto him, What hast thou done unto us? and what have I offended thee, that thou hast brought on me and on my kingdom a great sin? thou hast done deeds unto me that ought not to be done.', pt: 'Depois chamou Abimeleque a Abraão e disse-lhe: Que nos fizeste? E em que pequei eu contra ti, que trouxeste sobre mim e sobre o meu reino este grande pecado? Fizeste-me coisas que não se devem fazer.' },
    { v: 10, en: 'And Abimelech said unto Abraham, What sawest thou, that thou hast done this thing?', pt: 'Disse também Abimeleque a Abraão: Que viste para fazeres esta coisa?' },
    { v: 11, en: 'And Abraham said, Because I thought, Surely the fear of God is not in this place; and they will slay me for my wife\'s sake.', pt: 'E disse Abraão: Porque eu dizia: Certamente não há temor de Deus neste lugar, e me matarão por causa de minha mulher.' },
    { v: 12, en: 'And yet indeed she is my sister; she is the daughter of my father, but not the daughter of my mother; and she became my wife.', pt: 'E também na verdade ela é minha irmã; é filha de meu pai, mas não filha de minha mãe; e tornou-se minha mulher.' },
    { v: 13, en: 'And it came to pass, when God caused me to wander from my father\'s house, that I said unto her, This is thy kindness which thou shalt shew unto me; at every place whither we shall come, say of me, He is my brother.', pt: 'E quando Deus me fez sair errante da casa de meu pai, eu disse-lhe: Esta é a bondade que me farás; em todo o lugar onde chegarmos, dize de mim: Ele é meu irmão.' },
    { v: 14, en: 'And Abimelech took sheep, and oxen, and menservants, and womenservants, and gave them unto Abraham, and restored him Sarah his wife.', pt: 'E Abimeleque tomou ovelhas, e bois, e servos, e servas, e os deu a Abraão, e lhe restituiu Sara, sua mulher.' },
    { v: 15, en: 'And Abimelech said, Behold, my land is before thee: dwell where it pleaseth thee.', pt: 'E disse Abimeleque: Eis que a minha terra está diante de ti; habita onde te parecer bem.' },
    { v: 16, en: 'And unto Sarah he said, Behold, I have given thy brother a thousand pieces of silver: behold, he is to thee a covering of the eyes, unto all that are with thee, and with all other: thus she was reproved.', pt: 'E a Sara disse: Eis que dei mil peças de prata a teu irmão; eis que isso é para ti uma cobertura dos olhos a todos os que estão contigo, e perante todos; assim foste defendida.' },
    { v: 17, en: 'So Abraham prayed unto God: and God healed Abimelech, and his wife, and his maidservants; and they bare children.', pt: 'E Abraão orou a Deus; e Deus sarou a Abimeleque, e à sua mulher, e às suas servas; e deram à luz.' },
    { v: 18, en: 'For the LORD had fast closed up all the wombs of the house of Abimelech, because of Sarah Abraham\'s wife.', pt: 'Porque o Senhor havia fechado completamente todos os ventres da casa de Abimeleque, por causa de Sara, mulher de Abraão.' },
  ],
  21: [
    { v: 1, en: 'And the LORD visited Sarah as he had said, and the LORD did unto Sarah as he had spoken.', pt: 'E visitou o Senhor a Sara como dissera, e o Senhor fez a Sara como havia falado.' },
    { v: 2, en: 'For Sarah conceived, and bare Abraham a son in his old age, at the set time of which God had spoken to him.', pt: 'E Sara concebeu e deu a Abraão um filho na sua velhice, no tempo determinado de que Deus lhe havia falado.' },
    { v: 3, en: 'And Abraham called the name of his son that was born unto him, whom Sarah bare to him, Isaac.', pt: 'E Abraão chamou o nome do filho que lhe nasceu, que Sara lhe deu, Isaque.' },
    { v: 4, en: 'And Abraham circumcised his son Isaac being eight days old, as God had commanded him.', pt: 'E Abraão circuncidou o seu filho Isaque quando tinha oito dias de idade, como Deus lhe havia ordenado.' },
    { v: 5, en: 'And Abraham was an hundred years old, when his son Isaac was born unto him.', pt: 'E Abraão tinha cem anos quando lhe nasceu Isaque, seu filho.' },
    { v: 6, en: 'And Sarah said, God hath made me to laugh, so that all that hear will laugh with me.', pt: 'E disse Sara: Deus me fez rir, e todo o que ouvir se rirá comigo.' },
    { v: 7, en: 'And she said, Who would have said unto Abraham, that Sarah should have given children suck? for I have born him a son in his old age.', pt: 'E disse mais: Quem havia de dizer a Abraão que Sara havia de amamentar filhos? Pois dei-lhe um filho na sua velhice.' },
    { v: 8, en: 'And the child grew, and was weaned: and Abraham made a great feast the same day that Isaac was weaned.', pt: 'E cresceu o menino, e foi desmamado; e Abraão fez um grande banquete no dia em que foi desmamado Isaque.' },
    { v: 9, en: 'And Sarah saw the son of Hagar the Egyptian, which she had born unto Abraham, mocking.', pt: 'E viu Sara que o filho de Agar, a egípcia, que ela dera à luz a Abraão, zombava.' },
    { v: 10, en: 'Wherefore she said unto Abraham, Cast out this bondwoman and her son: for the son of this bondwoman shall not be heir with my son, even with Isaac.', pt: 'Portanto disse a Abraão: Lança fora esta serva e o seu filho; porque o filho desta serva não herdará com meu filho Isaque.' },
    { v: 11, en: 'And the thing was very grievous in Abraham\'s sight because of his son.', pt: 'E este negócio pareceu muito mau aos olhos de Abraão por causa de seu filho.' },
    { v: 12, en: 'And God said unto Abraham, Let it not be grievous in thy sight because of the lad, and because of thy bondwoman; in all that Sarah hath said unto thee, hearken unto her voice; for in Isaac shall thy seed be called.', pt: 'E disse Deus a Abraão: Não te pareça mau por causa do rapaz e por causa da tua serva; em tudo o que Sara te disser, ouve a sua voz; porque em Isaque será chamada a tua descendência.' },
    { v: 13, en: 'And also of the son of the bondwoman will I make a nation, because he is thy seed.', pt: 'E também do filho da serva farei uma nação, porque é tua descendência.' },
    { v: 14, en: 'And Abraham rose up early in the morning, and took bread, and a bottle of water, and gave it unto Hagar, putting it on her shoulder, and the child, and sent her away: and she departed, and wandered in the wilderness of Beersheba.', pt: 'E Abraão se levantou de madrugada, e tomou pão e um odre de água, e os deu a Agar, pondo-os sobre o seu ombro, com o menino, e a despediu; e ela partiu e vagueou pelo deserto de Berseba.' },
    { v: 15, en: 'And the water was spent in the bottle, and she cast the child under one of the shrubs.', pt: 'E quando a água do odre se acabou, ela lançou o menino debaixo de um dos arbustos.' },
    { v: 16, en: 'And she went, and sat her down over against him a good way off, as it were a bowshot: for she said, Let me not see the death of the child. And she sat over against him, and lift up her voice, and wept.', pt: 'E foi e assentou-se defronte, distante como um tiro de arco; porque disse: Não verei a morte do menino. E assentou-se defronte, e levantou a sua voz e chorou.' },
    { v: 17, en: 'And God heard the voice of the lad; and the angel of God called to Hagar out of heaven, and said unto her, What aileth thee, Hagar? fear not; for God hath heard the voice of the lad where he is.', pt: 'E Deus ouviu a voz do rapaz; e o anjo de Deus chamou Agar dos céus, e disse-lhe: Que tens, Agar? Não temas; porque Deus ouviu a voz do rapaz onde está.' },
    { v: 18, en: 'Arise, lift up the lad, and hold him in thine hand; for I will make him a great nation.', pt: 'Levanta-te, toma o rapaz e sustenta-o com a tua mão; porque eu o farei uma grande nação.' },
    { v: 19, en: 'And God opened her eyes, and she saw a well of water; and she went, and filled the bottle with water, and gave the lad drink.', pt: 'E Deus lhe abriu os olhos, e ela viu um poço de água; e foi e encheu o odre de água, e deu de beber ao rapaz.' },
    { v: 20, en: 'And God was with the lad; and he grew, and dwelt in the wilderness, and became an archer.', pt: 'E Deus era com o rapaz; e ele cresceu e habitou no deserto, e foi flecheiro.' },
    { v: 21, en: 'And he dwelt in the wilderness of Paran: and his mother took him a wife out of the land of Egypt.', pt: 'E habitou no deserto de Parã; e sua mãe lhe tomou por mulher uma mulher da terra do Egito.' },
    { v: 22, en: 'And it came to pass at that time, that Abimelech and Phichol the chief captain of his host spake unto Abraham, saying, God is with thee in all that thou doest.', pt: 'E aconteceu naquele tempo que Abimeleque e Ficol, chefe do seu exército, falaram a Abraão, dizendo: Deus é contigo em tudo o que fazes.' },
    { v: 23, en: 'Now therefore swear unto me here by God that thou wilt not deal falsely with me, nor with my son, nor with my son\'s son: but according to the kindness that I have done unto thee, thou shalt do unto me, and to the land wherein thou hast sojourned.', pt: 'Agora, pois, jura-me aqui por Deus que não usarás falsidade comigo, nem com meu filho, nem com meu neto; mas segundo a bondade que te fiz, farás a mim e à terra em que habitaste como estrangeiro.' },
    { v: 24, en: 'And Abraham said, I will swear.', pt: 'E disse Abraão: Eu juro.' },
    { v: 25, en: 'And Abraham reproved Abimelech because of a well of water, which Abimelech\'s servants had violently taken away.', pt: 'E Abraão repreendeu Abimeleque por causa de um poço de água que os servos de Abimeleque haviam roubado.' },
    { v: 26, en: 'And Abimelech said, I wot not who hath done this thing: neither didst thou tell me, neither yet heard I of it, but to day.', pt: 'E disse Abimeleque: Não sei quem fez esta coisa; também tu não mo disseste, nem eu ouvi falar nisso, senão hoje.' },
    { v: 27, en: 'And Abraham took sheep and oxen, and gave them unto Abimelech; and both of them made a covenant.', pt: 'E Abraão tomou ovelhas e bois, e os deu a Abimeleque; e os dois fizeram uma aliança.' },
    { v: 28, en: 'And Abraham set seven ewe lambs of the flock by themselves.', pt: 'E Abraão pôs à parte sete cordeiras do rebanho.' },
    { v: 29, en: 'And Abimelech said unto Abraham, What mean these seven ewe lambs which thou hast set by themselves?', pt: 'E disse Abimeleque a Abraão: Que significam estas sete cordeiras que puseste à parte?' },
    { v: 30, en: 'And he said, For these seven ewe lambs shalt thou take of my hand, that they may be a witness unto me, that I have digged this well.', pt: 'E ele disse: Tomarás estas sete cordeiras da minha mão, para que me sirvam de testemunho de que eu cavei este poço.' },
    { v: 31, en: 'Wherefore he called that place Beersheba; because there they sware both of them.', pt: 'Por isso chamou àquele lugar Berseba; porque ali os dois fizeram juramento.' },
    { v: 32, en: 'Thus they made a covenant at Beersheba: then Abimelech rose up, and Phichol the chief captain of his host, and they returned into the land of the Philistines.', pt: 'Assim fizeram aliança em Berseba; então levantou-se Abimeleque e Ficol, chefe do seu exército, e voltaram para a terra dos filisteus.' },
    { v: 33, en: 'And Abraham planted a grove in Beersheba, and called there on the name of the LORD, the everlasting God.', pt: 'E plantou Abraão um bosque em Berseba, e invocou ali o nome do Senhor, o Deus eterno.' },
    { v: 34, en: 'And Abraham sojourned in the Philistines\' land many days.', pt: 'E viveu Abraão como estrangeiro na terra dos filisteus muitos dias.' },
  ],
  22: [
    { v: 1, en: 'And it came to pass after these things, that God did tempt Abraham, and said unto him, Abraham: and he said, Behold, here I am.', pt: 'E aconteceu depois destas coisas que Deus tentou Abraão e disse-lhe: Abraão! E ele disse: Eis-me aqui.' },
    { v: 2, en: 'And he said, Take now thy son, thine only son Isaac, whom thou lovest, and get thee into the land of Moriah; and offer him there for a burnt offering upon one of the mountains which I will tell thee of.', pt: 'E disse: Toma agora o teu filho, o teu único filho Isaque, a quem amas, e vai-te à terra de Moriá, e oferece-o ali em holocausto sobre um dos montes que eu te designar.' },
    { v: 3, en: 'And Abraham rose up early in the morning, and saddled his ass, and took two of his young men with him, and Isaac his son, and clave the wood for the burnt offering, and rose up, and went unto the place of which God had told him.', pt: 'E Abraão se levantou de madrugada, e albardou o seu jumento, e tomou consigo dois dos seus moços e Isaque, seu filho; e racha a lenha para o holocausto, e levantou-se e foi ao lugar que Deus lhe havia designado.' },
    { v: 4, en: 'Then on the third day Abraham lifted up his eyes, and saw the place afar off.', pt: 'Ao terceiro dia, levantou Abraão os seus olhos, e viu o lugar ao longe.' },
    { v: 5, en: 'And Abraham said unto his young men, Abide ye here with the ass; and I and the lad will go yonder and worship, and come again to you.', pt: 'E disse Abraão aos seus moços: Ficai vós aqui com o jumento; e eu e o rapaz iremos até lá e adoraremos, e voltaremos a vós.' },
    { v: 6, en: 'And Abraham took the wood of the burnt offering, and laid it upon Isaac his son; and he took the fire in his hand, and a knife; and they went both of them together.', pt: 'E Abraão tomou a lenha do holocausto, e a pôs sobre Isaque, seu filho; e tomou na sua mão o fogo e o cutelo; e foram os dois juntos.' },
    { v: 7, en: 'And Isaac spake unto Abraham his father, and said, My father: and he said, Here am I, my son. And he said, Behold the fire and the wood: but where is the lamb for a burnt offering?', pt: 'E falou Isaque a Abraão, seu pai, e disse: Meu pai! E ele disse: Eis-me aqui, meu filho. E ele disse: Eis o fogo e a lenha; mas onde está o cordeiro para o holocausto?' },
    { v: 8, en: 'And Abraham said, My son, God will provide himself a lamb for a burnt offering: so they went both of them together.', pt: 'E disse Abraão: Deus proverá para si o cordeiro do holocausto, meu filho. E foram os dois juntos.' },
    { v: 9, en: 'And they came to the place which God had told him of; and Abraham built an altar there, and laid the wood in order, and bound Isaac his son, and laid him on the altar upon the wood.', pt: 'E chegaram ao lugar que Deus lhe havia dito; e Abraão edificou ali um altar, e pôs a lenha em ordem, e atou Isaque, seu filho, e o pôs sobre o altar em cima da lenha.' },
    { v: 10, en: 'And Abraham stretched forth his hand, and took the knife to slay his son.', pt: 'E Abraão estendeu a sua mão e tomou o cutelo para imolar o seu filho.' },
    { v: 11, en: 'And the angel of the LORD called unto him out of heaven, and said, Abraham, Abraham: and he said, Here am I.', pt: 'Mas o anjo do Senhor lhe chamou dos céus e disse: Abraão, Abraão! E ele disse: Eis-me aqui.' },
    { v: 12, en: 'And he said, Lay not thine hand upon the lad, neither do thou any thing unto him: for now I know that thou fearest God, seeing thou hast not withheld thy son, thine only son from me.', pt: 'E disse: Não estendas a tua mão sobre o rapaz, e não lhe faças nada; porque agora sei que temes a Deus, pois não me negaste o teu filho, o teu único filho.' },
    { v: 13, en: 'And Abraham lifted up his eyes, and looked, and behold behind him a ram caught in a thicket by his horns: and Abraham went and took the ram, and offered him up for a burnt offering in the stead of his son.', pt: 'E Abraão levantou os seus olhos e olhou, e eis que estava um carneiro atrás dele, preso pelos chifres num mato; e Abraão foi e tomou o carneiro, e o ofereceu em holocausto em lugar de seu filho.' },
    { v: 14, en: 'And Abraham called the name of that place Jehovahjireh: as it is said to this day, In the mount of the LORD it shall be seen.', pt: 'E Abraão chamou o nome daquele lugar: O Senhor proverá. Donde se diz até ao dia de hoje: No monte do Senhor se proverá.' },
    { v: 15, en: 'And the angel of the LORD called unto Abraham out of heaven the second time.', pt: 'E o anjo do Senhor chamou a Abraão dos céus segunda vez.' },
    { v: 16, en: 'And said, By myself have I sworn, saith the LORD, for because thou hast done this thing, and hast not withheld thy son, thine only son.', pt: 'E disse: Por mim mesmo juro, diz o Senhor, que, porque fizeste isto e não me negaste o teu filho, o teu único filho.' },
    { v: 17, en: 'That in blessing I will bless thee, and in multiplying I will multiply thy seed as the stars of the heaven, and as the sand which is upon the sea shore; and thy seed shall possess the gate of his enemies.', pt: 'Que te abençoarei muito, e multiplicarei muito a tua descendência como as estrelas dos céus e como a areia que está na praia do mar; e a tua descendência possuirá as portas dos seus inimigos.' },
    { v: 18, en: 'And in thy seed shall all the nations of the earth be blessed; because thou hast obeyed my voice.', pt: 'E em a tua descendência serão benditas todas as nações da terra, porque obedeceste à minha voz.' },
    { v: 19, en: 'So Abraham returned unto his young men, and they rose up and went together to Beersheba; and Abraham dwelt at Beersheba.', pt: 'E voltou Abraão aos seus moços; e levantaram-se e foram juntos a Berseba; e Abraão habitou em Berseba.' },
    { v: 20, en: 'And it came to pass after these things, that it was told Abraham, saying, Behold, Milcah, she hath also born children unto thy brother Nahor.', pt: 'E aconteceu depois destas coisas que foi anunciado a Abraão, dizendo: Eis que também Milca deu à luz filhos a Naor, teu irmão.' },
    { v: 21, en: 'Huz his firstborn, and Buz his brother, and Kemuel the father of Aram.', pt: 'Uz o seu primogênito, e Buz seu irmão, e Quemuel o pai de Arã.' },
    { v: 22, en: 'And Chesed, and Hazo, and Pildash, and Jidlaph, and Bethuel.', pt: 'E Quésede, e Hazo, e Pildas, e Jidlafe, e Betuel.' },
    { v: 23, en: 'And Bethuel begat Rebekah: these eight Milcah did bear to Nahor, Abraham\'s brother.', pt: 'E Betuel gerou Rebeca; estes oito Milca deu à luz a Naor, irmão de Abraão.' },
    { v: 24, en: 'And his concubine, whose name was Reumah, she bare also Tebah, and Gaham, and Thahash, and Maachah.', pt: 'E a sua concubina, cujo nome era Reumá, deu à luz também a Tebá, e Gaão, e Taas, e Maacá.' },
  ],
  23: [
    { v: 1, en: 'And Sarah was an hundred and seven and twenty years old: these were the years of the life of Sarah.', pt: 'E era Sara de cento e vinte e sete anos; estes foram os anos da vida de Sara.' },
    { v: 2, en: 'And Sarah died in Kirjatharba; the same is Hebron in the land of Canaan: and Abraham came to mourn for Sarah, and to weep for her.', pt: 'E Sara morreu em Quiriate-Arba, que é Hebrom, na terra de Canaã; e Abraão veio prantear Sara e a chorar por ela.' },
    { v: 3, en: 'And Abraham stood up from before his dead, and spake unto the sons of Heth, saying.', pt: 'E Abraão se levantou de diante do seu morto, e falou aos filhos de Hete, dizendo:' },
    { v: 4, en: 'I am a stranger and a sojourner with you: give me a possession of a buryingplace with you, that I may bury my dead out of my sight.', pt: 'Sou estrangeiro e peregrino entre vós; dai-me em propriedade um sepulcro entre vós, para que enterre o meu morto da minha presença.' },
    { v: 5, en: 'And the children of Heth answered Abraham, saying unto him.', pt: 'E os filhos de Hete responderam a Abraão, dizendo-lhe:' },
    { v: 6, en: 'Hear us, my lord: thou art a mighty prince among us: in the choice of our sepulchres bury thy dead; none of us shall withhold from thee his sepulchre, but that thou mayest bury thy dead.', pt: 'Ouve-nos, senhor meu; tu és um príncipe de Deus no meio de nós; no melhor dos nossos sepulcros enterra o teu morto; nenhum de nós te negará o seu sepulcro, para que enternes o teu morto.' },
    { v: 7, en: 'And Abraham stood up, and bowed himself to the people of the land, even to the children of Heth.', pt: 'E Abraão se levantou e se inclinou perante o povo da terra, perante os filhos de Hete.' },
    { v: 8, en: 'And he communed with them, saying, If it be your mind that I should bury my dead out of my sight; hear me, and intreat for me to Ephron the son of Zohar.', pt: 'E falou com eles, dizendo: Se for da vossa vontade que eu enterre o meu morto da minha presença, ouvi-me e intercedei por mim com Efrom, filho de Zoar.' },
    { v: 9, en: 'That he may give me the cave of Machpelah, which he hath, which is in the end of his field; for as much money as it is worth he shall give it me for a possession of a buryingplace amongst you.', pt: 'Para que me dê a caverna de Macpela, que tem, que está no extremo do seu campo; que por seu justo valor mo dê em propriedade de sepulcro entre vós.' },
    { v: 10, en: 'And Ephron dwelt among the children of Heth: and Ephron the Hittite answered Abraham in the audience of the children of Heth, even of all that went in at the gate of his city, saying.', pt: 'Ora, Efrom estava assentado no meio dos filhos de Hete; e Efrom, o heteu, respondeu a Abraão aos ouvidos dos filhos de Hete, de todos os que entravam pela porta da sua cidade, dizendo:' },
    { v: 11, en: 'Nay, my lord, hear me: the field give I thee, and the cave that is therein, I give it thee; in the presence of the sons of my people give I it thee: bury thy dead.', pt: 'Não, senhor meu, ouve-me; o campo te dou, e a caverna que nele está ta dou; na presença dos filhos do meu povo ta dou; enterra o teu morto.' },
    { v: 12, en: 'And Abraham bowed down himself before the people of the land.', pt: 'E Abraão se inclinou perante o povo da terra.' },
    { v: 13, en: 'And he spake unto Ephron in the audience of the people of the land, saying, But if thou wilt give it, I pray thee, hear me: I will give thee money for the field; take it of me, and I will bury my dead there.', pt: 'E falou a Efrom perante o povo da terra, dizendo: Mas se tu quiseres, peço-te que me ouças; darei o dinheiro pelo campo; recebe-o de mim, e enterrarei o meu morto ali.' },
    { v: 14, en: 'And Ephron answered Abraham, saying unto him.', pt: 'E respondeu Efrom a Abraão, dizendo-lhe:' },
    { v: 15, en: 'My lord, hearken unto me: the land is worth four hundred shekels of silver; what is that betwixt me and thee? bury therefore thy dead.', pt: 'Senhor meu, ouve-me; uma terra de quatrocentos siclos de prata, que é isso entre mim e ti? Enterra, pois, o teu morto.' },
    { v: 16, en: 'And Abraham hearkened unto Ephron; and Abraham weighed to Ephron the silver, which he had named in the audience of the sons of Heth, four hundred shekels of silver, current money with the merchant.', pt: 'E Abraão atendeu a Efrom; e Abraão pesou a Efrom a prata que ele nomeara aos ouvidos dos filhos de Hete, quatrocentos siclos de prata, na moeda corrente entre os mercadores.' },
    { v: 17, en: 'And the field of Ephron, which was in Machpelah, which was before Mamre, the field, and the cave which was therein, and all the trees that were in the field, that were in all the borders round about, were made sure.', pt: 'E o campo de Efrom, que estava em Macpela, em frente a Manre, o campo, e a caverna que nele estava, e todas as árvores que estavam no campo, em todos os seus termos em redor, foram confirmados.' },
    { v: 18, en: 'Unto Abraham for a possession in the presence of the children of Heth, before all that went in at the gate of his city.', pt: 'Para Abraão como propriedade, na presença dos filhos de Hete, perante todos os que entravam pela porta da sua cidade.' },
    { v: 19, en: 'And after this, Abraham buried Sarah his wife in the cave of the field of Machpelah before Mamre: the same is Hebron in the land of Canaan.', pt: 'E depois disto enterrou Abraão a Sara, sua mulher, na caverna do campo de Macpela, em frente a Manre, que é Hebrom, na terra de Canaã.' },
    { v: 20, en: 'And the field, and the cave that is therein, were made sure unto Abraham for a possession of a buryingplace by the sons of Heth.', pt: 'E o campo e a caverna que nele estava foram confirmados a Abraão como propriedade de sepulcro, pelos filhos de Hete.' },
  ],
  24: [
    { v: 1, en: 'And Abraham was old, and well stricken in age: and the LORD had blessed Abraham in all things.', pt: 'E Abraão era velho e avançado em dias; e o Senhor havia abençoado Abraão em tudo.' },
    { v: 2, en: 'And Abraham said unto his eldest servant of his house, that ruled over all that he had, Put, I pray thee, thy hand under my thigh.', pt: 'E disse Abraão ao seu servo, o mais velho da sua casa, que governava tudo o que tinha: Põe, peço-te, a tua mão debaixo da minha coxa.' },
    { v: 3, en: 'And I will make thee swear by the LORD, the God of heaven, and the God of the earth, that thou shalt not take a wife unto my son of the daughters of the Canaanites, among whom I dwell.', pt: 'E te farei jurar pelo Senhor, o Deus dos céus e o Deus da terra, que não tomarás para meu filho mulher das filhas dos cananeus, no meio dos quais eu habito.' },
    { v: 4, en: 'But thou shalt go unto my country, and to my kindred, and take a wife unto my son Isaac.', pt: 'Mas irás à minha terra e ao meu parentesco, e tomarás uma mulher para meu filho Isaque.' },
    { v: 5, en: 'And the servant said unto him, Peradventure the woman will not be willing to follow me unto this land: must I needs bring thy son again unto the land from whence thou camest?', pt: 'E disse-lhe o servo: Se porventura a mulher não quiser seguir-me para esta terra, devo eu de alguma maneira tornar a levar o teu filho para a terra donde saíste?' },
    { v: 6, en: 'And Abraham said unto him, Beware thou that thou bring not my son thither again.', pt: 'E disse-lhe Abraão: Guarda-te que não tornes a levar o meu filho para lá.' },
    { v: 7, en: 'The LORD God of heaven, which took me from my father\'s house, and from the land of my kindred, and which spake unto me, and that sware unto me, saying, Unto thy seed will I give this land; he shall send his angel before thee, and thou shalt take a wife unto my son from thence.', pt: 'O Senhor, o Deus dos céus, que me tirou da casa de meu pai e da terra da minha família, e que me falou e me jurou, dizendo: À tua descendência darei esta terra; ele enviará o seu anjo à tua frente, e tomarás de lá uma mulher para meu filho.' },
    { v: 8, en: 'And if the woman will not be willing to follow thee, then thou shalt be clear from this my oath: only bring not my son thither again.', pt: 'E se a mulher não quiser seguir-te, então serás livre deste meu juramento; somente não leves o meu filho de volta para lá.' },
    { v: 9, en: 'And the servant put his hand under the thigh of Abraham his master, and sware to him concerning that matter.', pt: 'E o servo pôs a sua mão debaixo da coxa de Abraão, seu senhor, e lhe jurou acerca deste negócio.' },
    { v: 10, en: 'And the servant took ten camels of the camels of his master, and departed; for all the goods of his master were in his hand: and he arose, and went to Mesopotamia, unto the city of Nahor.', pt: 'E o servo tomou dez camelos dos camelos de seu senhor, e partiu, pois todos os bens de seu senhor estavam na sua mão; e levantou-se e foi à Mesopotâmia, à cidade de Naor.' },
    { v: 11, en: 'And he made his camels to kneel down without the city by a well of water at the time of the evening, even the time that women go out to draw water.', pt: 'E fez ajoelhar os camelos fora da cidade, junto a um poço de água, à tarde, ao tempo em que as mulheres saem a tirar água.' },
    { v: 12, en: 'And he said, O LORD God of my master Abraham, I pray thee, send me good speed this day, and shew kindness unto my master Abraham.', pt: 'E disse: Ó Senhor, Deus de meu senhor Abraão, peço-te que me faças encontrar o que procuro hoje, e que uses bondade para com meu senhor Abraão.' },
    { v: 13, en: 'Behold, I stand here by the well of water; and the daughters of the men of the city come out to draw water.', pt: 'Eis que estou junto à fonte de água, e as filhas dos homens da cidade saem a tirar água.' },
    { v: 14, en: 'And let it come to pass, that the damsel to whom I shall say, Let down thy pitcher, I pray thee, that I may drink; and she shall say, Drink, and I will give thy camels drink also: let the same be she that thou hast appointed for thy servant Isaac; and thereby shall I know that thou hast shewed kindness unto my master.', pt: 'E seja a donzela a quem eu disser: Abaixa a tua cântara, peço-te, para eu beber; e ela disser: Bebe, e darei de beber também aos teus camelos; seja ela a que ordenaste para o teu servo Isaque; e por isso saberei que usaste bondade para com meu senhor.' },
    { v: 15, en: 'And it came to pass, before he had done speaking, that, behold, Rebekah came out, who was born to Bethuel, son of Milcah, the wife of Nahor, Abraham\'s brother, with her pitcher upon her shoulder.', pt: 'E aconteceu que, antes que acabasse de falar, eis que saiu Rebeca, que nascera a Betuel, filho de Milca, mulher de Naor, irmão de Abraão, com a sua cântara sobre o seu ombro.' },
    { v: 16, en: 'And the damsel was very fair to look upon, a virgin, neither had any man known her: and she went down to the well, and filled her pitcher, and came up.', pt: 'E a donzela era de muito formosa aparência, virgem, e nenhum homem a havia conhecido; e desceu à fonte, e encheu a sua cântara, e tornou a subir.' },
    { v: 17, en: 'And the servant ran to meet her, and said, Let me, I pray thee, drink a little water of thy pitcher.', pt: 'E o servo correu ao seu encontro, e disse: Deixa-me beber um pouco de água da tua cântara.' },
    { v: 18, en: 'And she said, Drink, my lord: and she hasted, and let down her pitcher upon her hand, and gave him drink.', pt: 'E ela disse: Bebe, senhor meu; e se apressou e abaixou a sua cântara sobre a sua mão, e lhe deu de beber.' },
    { v: 19, en: 'And when she had done giving him drink, she said, I will draw water for thy camels also, until they have done drinking.', pt: 'E quando acabou de lhe dar de beber, disse: Também tirarei água para os teus camelos, até que acabem de beber.' },
    { v: 20, en: 'And she hasted, and emptied her pitcher into the trough, and ran again unto the well to draw water, and drew for all his camels.', pt: 'E se apressou e despejou a sua cântara no cocho, e correu outra vez ao poço a tirar água, e tirou para todos os seus camelos.' },
    { v: 21, en: 'And the man wondering at her held his peace, to wit whether the LORD had made his journey prosperous or not.', pt: 'E o homem a contemplava em silêncio, para saber se o Senhor havia prosperado a sua viagem ou não.' },
    { v: 22, en: 'And it came to pass, as the camels had done drinking, that the man took a golden earring of half a shekel weight, and two bracelets for her hands of ten shekels weight of gold.', pt: 'E aconteceu que, quando os camelos acabaram de beber, o homem tomou um pendente de ouro de meio siclo de peso, e duas pulseiras para as suas mãos, de dez siclos de peso de ouro.' },
    { v: 23, en: 'And said, Whose daughter art thou? tell me, I pray thee: is there room in thy father\'s house for us to lodge in?', pt: 'E disse: De quem és filha? Dize-me, peço-te; há na casa de teu pai lugar para nós pousarmos?' },
    { v: 24, en: 'And she said unto him, I am the daughter of Bethuel the son of Milcah, which she bare unto Nahor.', pt: 'E ela disse-lhe: Sou filha de Betuel, filho de Milca, que ela deu à luz a Naor.' },
    { v: 25, en: 'She said moreover unto him, We have both straw and provender enough, and room to lodge in.', pt: 'Disse-lhe ainda: Temos palha e muito pasto, e também lugar para pousar.' },
    { v: 26, en: 'And the man bowed down his head, and worshipped the LORD.', pt: 'E o homem se inclinou e adorou o Senhor.' },
    { v: 27, en: 'And he said, Blessed be the LORD God of my master Abraham, who hath not left destitute my master of his mercy and his truth: I being in the way, the LORD led me to the house of my master\'s brethren.', pt: 'E disse: Bendito seja o Senhor, o Deus de meu senhor Abraão, que não retirou a sua misericórdia e a sua verdade de meu senhor; estando eu no caminho, o Senhor me guiou à casa dos irmãos de meu senhor.' },
    { v: 28, en: 'And the damsel ran, and told them of her mother\'s house these things.', pt: 'E a donzela correu e contou essas coisas na casa de sua mãe.' },
    { v: 29, en: 'And Rebekah had a brother, and his name was Laban: and Laban ran out unto the man, unto the well.', pt: 'E Rebeca tinha um irmão, cujo nome era Labão; e Labão correu para fora ao homem, ao poço.' },
    { v: 30, en: 'And it came to pass, when he saw the earring and bracelets upon his sister\'s hands, and when he heard the words of Rebekah his sister, saying, Thus spake the man unto me; that he came unto the man; and, behold, he stood by the camels at the well.', pt: 'E aconteceu que, quando viu o pendente e as pulseiras nas mãos de sua irmã, e quando ouviu as palavras de Rebeca, sua irmã, dizendo: Assim me falou o homem; veio ao homem; e eis que ele estava em pé junto aos camelos, no poço.' },
    { v: 31, en: 'And he said, Come in, thou blessed of the LORD; wherefore standest thou without? for I have prepared the house, and room for the camels.', pt: 'E disse: Entra, bendito do Senhor; por que ficas em pé de fora? Pois já preparei a casa, e lugar para os camelos.' },
    { v: 32, en: 'And the man came into the house: and he ungirded his camels, and gave straw and provender for the camels, and water to wash his feet, and the men\'s feet that were with him.', pt: 'E o homem entrou na casa; e Labão desalbardou os camelos, e deu palha e pasto aos camelos, e água para lavar os pés dele e dos homens que estavam com ele.' },
    { v: 33, en: 'And there was set meat before him to eat: but he said, I will not eat, until I have told mine errand. And he said, Speak on.', pt: 'E puseram-lhe comida diante dele para comer; mas ele disse: Não comerei até que tenha dito o meu recado. E disse: Fala.' },
    { v: 34, en: 'And he said, I am Abraham\'s servant.', pt: 'E ele disse: Sou servo de Abraão.' },
    { v: 35, en: 'And the LORD hath blessed my master greatly; and he is become great: and he hath given him flocks, and herds, and silver, and gold, and menservants, and maidservants, and camels, and asses.', pt: 'E o Senhor abençoou muito a meu senhor, e ele prosperou; e lhe deu ovelhas e bois, e prata e ouro, e servos e servas, e camelos e jumentos.' },
    { v: 36, en: 'And Sarah my master\'s wife bare a son to my master when she was old: and unto him hath he given all that he hath.', pt: 'E Sara, mulher de meu senhor, deu à luz um filho a meu senhor na sua velhice; e a ele deu tudo o que tem.' },
    { v: 37, en: 'And my master made me swear, saying, Thou shalt not take a wife to my son of the daughters of the Canaanites, in whose land I dwell.', pt: 'E meu senhor me fez jurar, dizendo: Não tomarás para meu filho uma mulher das filhas dos cananeus, em cuja terra habito.' },
    { v: 38, en: 'But thou shalt go unto my father\'s house, and to my kindred, and take a wife unto my son.', pt: 'Mas irás à casa de meu pai e ao meu parentesco, e tomarás uma mulher para meu filho.' },
    { v: 39, en: 'And I said unto my master, Peradventure the woman will not follow me.', pt: 'E eu disse a meu senhor: Porventura a mulher não me seguirá.' },
    { v: 40, en: 'And he said unto me, The LORD, before whom I walk, will send his angel with thee, and prosper thy way; and thou shalt take a wife for my son of my kindred, and of my father\'s house.', pt: 'E ele me disse: O Senhor, perante quem ando, enviará o seu anjo contigo, e prosperará a tua viagem; e tomarás para meu filho uma mulher do meu parentesco e da casa de meu pai.' },
    { v: 41, en: 'Then shalt thou be clear from this my oath, when thou comest to my kindred; and if they give not thee one, thou shalt be clear from my oath.', pt: 'Então serás livre do meu juramento quando chegares ao meu parentesco; e se não to derem, serás livre do meu juramento.' },
    { v: 42, en: 'And I came this day unto the well, and said, O LORD God of my master Abraham, if now thou do prosper my way which I go.', pt: 'E vim hoje ao poço e disse: Ó Senhor, Deus de meu senhor Abraão, se agora prosperares a viagem que faço.' },
    { v: 43, en: 'Behold, I stand by the well of water; and it shall come to pass, that when the virgin cometh forth to draw water, and I say to her, Give me, I pray thee, a little water of thy pitcher to drink.', pt: 'Eis que estou junto à fonte de água; e acontecerá que quando a donzela sair a tirar água, eu lhe diga: Dá-me, peço-te, um pouco de água da tua cântara para beber.' },
    { v: 44, en: 'And she say to me, Both drink thou, and I will also draw for thy camels: let the same be the woman whom the LORD hath appointed out for my master\'s son.', pt: 'E ela me diga: Bebe tu, e também tirarei água para os teus camelos; seja ela a mulher que o Senhor destinou para o filho de meu senhor.' },
    { v: 45, en: 'And before I had done speaking in mine heart, behold, Rebekah came forth with her pitcher on her shoulder; and she went down unto the well, and drew water: and I said unto her, Let me drink, I pray thee.', pt: 'Antes que eu acabasse de falar no meu coração, eis que Rebeca saiu com a sua cântara sobre o ombro; e desceu ao poço e tirou água; e eu lhe disse: Dá-me de beber, peço-te.' },
    { v: 46, en: 'And she made haste, and let down her pitcher from her shoulder, and said, Drink, and I will give thy camels drink also: so I drank, and she made the camels drink also.', pt: 'E ela se apressou e tirou a cântara do seu ombro, e disse: Bebe, e darei de beber também aos teus camelos. Então bebi, e ela deu de beber também aos camelos.' },
    { v: 47, en: 'And I asked her, and said, Whose daughter art thou? And she said, The daughter of Bethuel, Nahor\'s son, whom Milcah bare unto him: and I put the earring upon her face, and the bracelets upon her hands.', pt: 'E eu lhe perguntei e disse: De quem és filha? E ela disse: Filha de Betuel, filho de Naor, que Milca lhe deu à luz. E eu lhe pus o pendente no rosto e as pulseiras nas mãos.' },
    { v: 48, en: 'And I bowed down my head, and worshipped the LORD, and blessed the LORD God of my master Abraham, which had led me in the right way to take my master\'s brother\'s daughter unto his son.', pt: 'E me inclinei e adorei o Senhor, e bendisse o Senhor, o Deus de meu senhor Abraão, que me guiou pelo caminho certo para tomar a filha do irmão de meu senhor para seu filho.' },
    { v: 49, en: 'And now if ye will deal kindly and truly with my master, tell me: and if not, tell me; that I may turn to the right hand, or to the left.', pt: 'E agora, se quereis usar de bondade e lealdade para com meu senhor, dizei-mo; e se não, dizei-mo também, para que me volte para a direita ou para a esquerda.' },
    { v: 50, en: 'Then Laban and Bethuel answered and said, The thing proceedeth from the LORD: we cannot speak unto thee bad or good.', pt: 'Então responderam Labão e Betuel e disseram: Da parte do Senhor saiu este negócio; não te podemos responder nem mal nem bem.' },
    { v: 51, en: 'Behold, Rebekah is before thee, take her, and go, and let her be thy master\'s son\'s wife, as the LORD hath spoken.', pt: 'Eis que Rebeca está diante de ti; toma-a e vai-te, e seja ela mulher do filho de teu senhor, como o Senhor falou.' },
    { v: 52, en: 'And it came to pass, that, when Abraham\'s servant heard their words, he worshipped the LORD, bowing himself to the earth.', pt: 'E aconteceu que, quando o servo de Abraão ouviu as palavras deles, adorou o Senhor, inclinando-se em terra.' },
    { v: 53, en: 'And the servant brought forth jewels of silver, and jewels of gold, and raiment, and gave them to Rebekah: he gave also to her brother and to her mother precious things.', pt: 'E o servo trouxe joias de prata e joias de ouro e vestes, e as deu a Rebeca; também deu coisas preciosas a seu irmão e à sua mãe.' },
    { v: 54, en: 'And they did eat and drink, he and the men that were with him, and tarried all night; and they rose up in the morning, and he said, Send me away unto my master.', pt: 'E comeram e beberam, ele e os homens que estavam com ele, e passaram a noite ali; e levantaram-se pela manhã, e ele disse: Mandai-me ir a meu senhor.' },
    { v: 55, en: 'And her brother and her mother said, Let the damsel abide with us a few days, at the least ten; after that she shall go.', pt: 'E disse seu irmão e sua mãe: Fique a donzela conosco pelo menos uns dez dias; depois irá.' },
    { v: 56, en: 'And he said unto them, Hinder me not, seeing the LORD hath prospered my way; send me away that I may go to my master.', pt: 'E ele lhes disse: Não me detenhais, pois o Senhor prosperou a minha viagem; mandai-me ir para que vá a meu senhor.' },
    { v: 57, en: 'And they said, We will call the damsel, and enquire at her mouth.', pt: 'E disseram: Chamemos a donzela e perguntemo-lo à sua boca.' },
    { v: 58, en: 'And they called Rebekah, and said unto her, Wilt thou go with this man? And she said, I will go.', pt: 'E chamaram Rebeca e lhe disseram: Irás com este homem? E ela disse: Irei.' },
    { v: 59, en: 'And they sent away Rebekah their sister, and her nurse, and Abraham\'s servant, and his men.', pt: 'E despediram Rebeca, sua irmã, com a sua ama, e o servo de Abraão, e os seus homens.' },
    { v: 60, en: 'And they blessed Rebekah, and said unto her, Thou art our sister, be thou the mother of thousands of millions, and let thy seed possess the gate of those which hate them.', pt: 'E abençoaram a Rebeca e disseram-lhe: Tu és nossa irmã; sê mãe de milhares de milhares, e que a tua descendência possua as portas dos seus inimigos.' },
    { v: 61, en: 'And Rebekah arose, and her damsels, and they rode upon the camels, and followed the man: and the servant took Rebekah, and went his way.', pt: 'E levantou-se Rebeca e as suas moças, e montaram sobre os camelos e seguiram o homem; e o servo tomou Rebeca e foi-se.' },
    { v: 62, en: 'And Isaac came from the way of the well Lahairoi; for he dwelt in the south country.', pt: 'E Isaque vinha do caminho do poço Laai-Roi; porque habitava no sul.' },
    { v: 63, en: 'And Isaac went out to meditate in the field at the eventide: and he lifted up his eyes, and saw, and, behold, the camels were coming.', pt: 'E Isaque saíra a passear pelo campo, ao cair da tarde; e levantou os seus olhos e viu, e eis que os camelos vinham.' },
    { v: 64, en: 'And Rebekah lifted up her eyes, and when she saw Isaac, she lighted off the camel.', pt: 'E Rebeca levantou os seus olhos, e quando viu a Isaque, desceu do camelo.' },
    { v: 65, en: 'For she had said unto the servant, What man is this that walketh in the field to meet us? And the servant had said, It is my master: therefore she took a vail, and covered herself.', pt: 'E ela dissera ao servo: Quem é esse homem que vem pelo campo ao nosso encontro? E o servo dissera: É meu senhor. E ela tomou o véu e se cobriu.' },
    { v: 66, en: 'And the servant told Isaac all things that he had done.', pt: 'E o servo contou a Isaque todas as coisas que havia feito.' },
    { v: 67, en: 'And Isaac brought her into his mother Sarah\'s tent, and took Rebekah, and she became his wife; and he loved her: and Isaac was comforted after his mother\'s death.', pt: 'E Isaque a trouxe para a tenda de Sara, sua mãe, e tomou Rebeca, e ela se tornou sua mulher; e ele a amou; e Isaque foi consolado depois da morte de sua mãe.' },
  ],
  25: [
    { v: 1, en: 'Then again Abraham took a wife, and her name was Keturah.', pt: 'E Abraão tornou a casar, e o nome de sua mulher era Quetura.' },
    { v: 2, en: 'And she bare him Zimran, and Jokshan, and Medan, and Midian, and Ishbak, and Shuah.', pt: 'E ela lhe deu à luz a Zinrã, e Jocsã, e Medã, e Midiã, e Isbaque, e Suá.' },
    { v: 3, en: 'And Jokshan begat Sheba, and Dedan. And the sons of Dedan were Asshurim, and Letushim, and Leummim.', pt: 'E Jocsã gerou a Sebá e a Dedã; e os filhos de Dedã foram Assurins, e Letusins, e Leumins.' },
    { v: 4, en: 'And the sons of Midian; Ephah, and Epher, and Hanoch, and Abida, and Eldaah. All these were the children of Keturah.', pt: 'E os filhos de Midiã: Efá, e Efer, e Hanoque, e Abida, e Eldaá; todos estes foram filhos de Quetura.' },
    { v: 5, en: 'And Abraham gave all that he had unto Isaac.', pt: 'E Abraão deu tudo o que tinha a Isaque.' },
    { v: 6, en: 'But unto the sons of the concubines, which Abraham had, Abraham gave gifts, and sent them away from Isaac his son, while he yet lived, eastward, unto the east country.', pt: 'Mas aos filhos das concubinas que Abraão tinha, Abraão deu presentes, e os mandou embora de Isaque, seu filho, enquanto ainda estava vivo, para o leste, para a terra do oriente.' },
    { v: 7, en: 'And these are the days of the years of Abraham\'s life which he lived, an hundred threescore and fifteen years.', pt: 'E estes são os dias dos anos da vida de Abraão que ele viveu: cento e setenta e cinco anos.' },
    { v: 8, en: 'Then Abraham gave up the ghost, and died in a good old age, an old man, and full of years; and was gathered to his people.', pt: 'E Abraão expirou e morreu em boa velhice, velho e satisfeito de anos, e foi reunido ao seu povo.' },
    { v: 9, en: 'And his sons Isaac and Ishmael buried him in the cave of Machpelah, in the field of Ephron the son of Zohar the Hittite, which is before Mamre.', pt: 'E seus filhos Isaque e Ismael o sepultaram na caverna de Macpela, no campo de Efrom, filho de Zoar, o heteu, que está em frente a Manre.' },
    { v: 10, en: 'The field which Abraham purchased of the sons of Heth: there was Abraham buried, and Sarah his wife.', pt: 'O campo que Abraão comprou dos filhos de Hete; ali foi Abraão sepultado, e Sara, sua mulher.' },
    { v: 11, en: 'And it came to pass after the death of Abraham, that God blessed his son Isaac; and Isaac dwelt by the well Lahairoi.', pt: 'E aconteceu depois da morte de Abraão que Deus abençoou a Isaque, seu filho; e Isaque habitou junto ao poço Laai-Roi.' },
    { v: 12, en: 'Now these are the generations of Ishmael, Abraham\'s son, whom Hagar the Egyptian, Sarah\'s handmaid, bare unto Abraham.', pt: 'E estas são as gerações de Ismael, filho de Abraão, que Agar, a egípcia, serva de Sara, deu à luz a Abraão.' },
    { v: 13, en: 'And these are the names of the sons of Ishmael, by their names, according to their generations: the firstborn of Ishmael, Nebajoth; and Kedar, and Adbeel, and Mibsam.', pt: 'E estes são os nomes dos filhos de Ismael, pelos seus nomes, segundo as suas gerações: o primogênito de Ismael, Nebaiote; e Cedar, e Adbeel, e Mibsã.' },
    { v: 14, en: 'And Mishma, and Dumah, and Massa.', pt: 'E Misma, e Dumá, e Massá.' },
    { v: 15, en: 'Hadar, and Tema, Jetur, Naphish, and Kedemah.', pt: 'Hadade, e Temá, Jetur, Nafis e Quedema.' },
    { v: 16, en: 'These are the sons of Ishmael, and these are their names, by their towns, and by their castles; twelve princes according to their nations.', pt: 'Estes são os filhos de Ismael, e estes são os seus nomes, pelas suas aldeias e pelos seus castelos; doze príncipes segundo as suas nações.' },
    { v: 17, en: 'And these are the years of the life of Ishmael, an hundred and thirty and seven years: and he gave up the ghost and died; and was gathered unto his people.', pt: 'E estes são os anos da vida de Ismael: cento e trinta e sete anos; e expirou e morreu, e foi reunido ao seu povo.' },
    { v: 18, en: 'And they dwelt from Havilah unto Shur, that is before Egypt, as thou goest toward Assyria: and he died in the presence of all his brethren.', pt: 'E habitaram desde Havilá até Sur, que está em frente do Egito, na direção da Assíria; e estabeleceu-se em frente de todos os seus irmãos.' },
    { v: 19, en: 'And these are the generations of Isaac, Abraham\'s son: Abraham begat Isaac.', pt: 'E estas são as gerações de Isaque, filho de Abraão; Abraão gerou a Isaque.' },
    { v: 20, en: 'And Isaac was forty years old when he took Rebekah to wife, the daughter of Bethuel the Syrian of Padanaram, the sister to Laban the Syrian.', pt: 'E tinha Isaque quarenta anos quando tomou por mulher a Rebeca, filha de Betuel, o arameu de Padã-Arã, irmã de Labão, o arameu.' },
    { v: 21, en: 'And Isaac intreated the LORD for his wife, because she was barren: and the LORD was intreated of him, and Rebekah his wife conceived.', pt: 'E Isaque orou ao Senhor por sua mulher, porque era estéril; e o Senhor o atendeu, e Rebeca, sua mulher, concebeu.' },
    { v: 22, en: 'And the children struggled together within her; and she said, If it be so, why am I thus? And she went to enquire of the LORD.', pt: 'E os filhos se chocavam dentro dela; e ela disse: Se assim é, por que estou assim? E foi perguntar ao Senhor.' },
    { v: 23, en: 'And the LORD said unto her, Two nations are in thy womb, and two manner of people shall be separated from thy bowels; and the one people shall be stronger than the other people; and the elder shall serve the younger.', pt: 'E disse-lhe o Senhor: Duas nações estão no teu ventre, e dois povos se dividirão das tuas entranhas; um povo será mais forte do que o outro, e o maior servirá ao menor.' },
    { v: 24, en: 'And when her days to be delivered were fulfilled, behold, there were twins in her womb.', pt: 'E quando se cumpriram os seus dias para dar à luz, eis que havia gêmeos no seu ventre.' },
    { v: 25, en: 'And the first came out red, all over like an hairy garment; and they called his name Esau.', pt: 'E saiu o primeiro, ruivo, todo como um manto de pelos; e chamaram o seu nome Esaú.' },
    { v: 26, en: 'And after that came his brother out, and his hand took hold on Esau\'s heel; and his name was called Jacob: and Isaac was threescore years old when she bare them.', pt: 'E depois saiu seu irmão, com a sua mão segurando o calcanhar de Esaú; e foi chamado o seu nome Jacó; e Isaque tinha sessenta anos quando ela os deu à luz.' },
    { v: 27, en: 'And the boys grew: and Esau was a cunning hunter, a man of the field; and Jacob was a plain man, dwelling in tents.', pt: 'E cresceram os meninos; e Esaú foi hábil caçador, homem do campo; e Jacó era homem simples, que habitava em tendas.' },
    { v: 28, en: 'And Isaac loved Esau, because he did eat of his venison: but Rebekah loved Jacob.', pt: 'E Isaque amava a Esaú, porque comia da sua caça; mas Rebeca amava a Jacó.' },
    { v: 29, en: 'And Jacob sod pottage: and Esau came from the field, and he was faint.', pt: 'E Jacó cozia um guisado; e Esaú veio do campo, e estava exausto.' },
    { v: 30, en: 'And Esau said to Jacob, Feed me, I pray thee, with that same red pottage; for I am faint: therefore was his name called Edom.', pt: 'E disse Esaú a Jacó: Dá-me a comer desse guisado vermelho, pois estou exausto; por isso foi chamado o seu nome Edom.' },
    { v: 31, en: 'And Jacob said, Sell me this day thy birthright.', pt: 'E disse Jacó: Vende-me hoje a tua primogenitura.' },
    { v: 32, en: 'And Esau said, Behold, I am at the point to die: and what profit shall this birthright do to me?', pt: 'E disse Esaú: Eis que estou a ponto de morrer; e de que me serve a primogenitura?' },
    { v: 33, en: 'And Jacob said, Swear to me this day; and he sware unto him: and he sold his birthright unto Jacob.', pt: 'E disse Jacó: Jura-me hoje. E ele lhe jurou; e vendeu a sua primogenitura a Jacó.' },
    { v: 34, en: 'Then Jacob gave Esau bread and pottage of lentiles; and he did eat and drink, and rose up, and went his way: so Esau despised his birthright.', pt: 'E Jacó deu a Esaú pão e guisado de lentilhas; e ele comeu e bebeu, e levantou-se e foi-se; assim desprezou Esaú a sua primogenitura.' },
  ],
  26: [
    { v: 1, en: 'And there was a famine in the land, beside the first famine that was in the days of Abraham. And Isaac went unto Abimelech king of the Philistines unto Gerar.', pt: 'E houve fome na terra, além da primeira fome que houve nos dias de Abraão; e Isaque foi a Abimeleque, rei dos filisteus, a Gerar.' },
    { v: 2, en: 'And the LORD appeared unto him, and said, Go not down into Egypt; dwell in the land which I shall tell thee of.', pt: 'E o Senhor apareceu a ele e disse: Não desças ao Egito; habita na terra que eu te disser.' },
    { v: 3, en: 'Sojourn in this land, and I will be with thee, and will bless thee; for unto thee, and unto thy seed, I will give all these countries, and I will perform the oath which I sware unto Abraham thy father.', pt: 'Peregrina nesta terra, e eu serei contigo e te abençoarei; porque a ti e à tua descendência darei todas estas terras, e confirmarei o juramento que fiz a Abraão, teu pai.' },
    { v: 4, en: 'And I will make thy seed to multiply as the stars of heaven, and will give unto thy seed all these countries; and in thy seed shall all the nations of the earth be blessed.', pt: 'E multiplicarei a tua descendência como as estrelas dos céus, e darei à tua descendência todas estas terras; e em a tua descendência serão benditas todas as nações da terra.' },
    { v: 5, en: 'Because that Abraham obeyed my voice, and kept my charge, my commandments, my statutes, and my laws.', pt: 'Porquanto Abraão obedeceu à minha voz, e guardou a minha ordenança, os meus mandamentos, os meus estatutos e as minhas leis.' },
    { v: 6, en: 'And Isaac dwelt in Gerar.', pt: 'E habitou Isaque em Gerar.' },
    { v: 7, en: 'And the men of the place asked him of his wife; and he said, She is my sister: for he feared to say, She is my wife; lest, said he, the men of the place should kill me for Rebekah; because she was fair to look upon.', pt: 'E os homens do lugar lhe perguntaram acerca de sua mulher; e ele disse: Ela é minha irmã; porque teve medo de dizer: É minha mulher; para que, disse ele, os homens do lugar não me matem por causa de Rebeca; porque era de formosa aparência.' },
    { v: 8, en: 'And it came to pass, when he had been there a long time, that Abimelech king of the Philistines looked out at a window, and saw, and, behold, Isaac was sporting with Rebekah his wife.', pt: 'E aconteceu que, quando ele estava lá há muito tempo, Abimeleque, rei dos filisteus, olhou por uma janela, e viu; e eis que Isaque acariciava Rebeca, sua mulher.' },
    { v: 9, en: 'And Abimelech called Isaac, and said, Behold, of a surety she is thy wife: and how saidst thou, She is my sister? And Isaac said unto him, Because I said, Lest I die for her.', pt: 'E Abimeleque chamou Isaque e disse: Certamente ela é tua mulher; e como disseste: Ela é minha irmã? E disse-lhe Isaque: Porque eu dizia: Para que não morra por causa dela.' },
    { v: 10, en: 'And Abimelech said, What is this thou hast done unto us? one of the people might lightly have lien with thy wife, and thou shouldest have brought guiltiness upon us.', pt: 'E disse Abimeleque: Que é isto que nos fizeste? Facilmente alguém do povo poderia ter-se deitado com a tua mulher, e terias trazido sobre nós culpa.' },
    { v: 11, en: 'And Abimelech charged all his people, saying, He that toucheth this man or his wife shall surely be put to death.', pt: 'E Abimeleque ordenou a todo o seu povo, dizendo: Quem tocar neste homem ou em sua mulher certamente morrerá.' },
    { v: 12, en: 'Then Isaac sowed in that land, and received in the same year an hundredfold: and the LORD blessed him.', pt: 'E Isaque semeou naquela terra, e naquele ano colheu cento por um; e o Senhor o abençoou.' },
    { v: 13, en: 'And the man waxed great, and went forward, and grew until he became very great.', pt: 'E o homem se engrandeceu, e foi crescendo até se tornar muito grande.' },
    { v: 14, en: 'For he had possession of flocks, and possession of herds, and great store of servants: and the Philistines envied him.', pt: 'E tinha rebanhos de ovelhas e rebanhos de bois e muitos servos; e os filisteus o invejaram.' },
    { v: 15, en: 'For all the wells which his father\'s servants had digged in the days of Abraham his father, the Philistines had stopped them, and filled them with earth.', pt: 'E todos os poços que os servos de seu pai cavaram nos dias de Abraão, seu pai, os filisteus os taparam e encheram de terra.' },
    { v: 16, en: 'And Abimelech said unto Isaac, Go from us; for thou art much mightier than we.', pt: 'E disse Abimeleque a Isaque: Vai-te de nós; porque te tornaste muito mais poderoso do que nós.' },
    { v: 17, en: 'And Isaac departed thence, and pitched his tent in the valley of Gerar, and dwelt there.', pt: 'E Isaque partiu dali, e armou a sua tenda no vale de Gerar, e habitou lá.' },
    { v: 18, en: 'And Isaac digged again the wells of water, which they had digged in the days of Abraham his father; for the Philistines had stopped them after the death of Abraham: and he called their names after the names by which his father had called them.', pt: 'E Isaque tornou a cavar os poços de água que cavaram nos dias de Abraão, seu pai, e que os filisteus taparam depois da morte de Abraão; e lhes chamou pelos nomes que seu pai lhes havia chamado.' },
    { v: 19, en: 'And Isaac\'s servants digged in the valley, and found there a well of springing water.', pt: 'E os servos de Isaque cavaram no vale, e acharam ali um poço de água viva.' },
    { v: 20, en: 'And the herdmen of Gerar did strive with Isaac\'s herdmen, saying, The water is ours: and he called the name of the well Esek; because they strove with him.', pt: 'E os pastores de Gerar contenderam com os pastores de Isaque, dizendo: A água é nossa. E chamou o nome do poço Eseque, porque contenderam com ele.' },
    { v: 21, en: 'And they digged another well, and strove for that also: and he called the name of it Sitnah.', pt: 'E cavaram outro poço, e contenderam também por ele; e chamou o seu nome Siná.' },
    { v: 22, en: 'And he removed from thence, and digged another well; and for that they strove not: and he called the name of it Rehoboth; and he said, For now the LORD hath made room for us, and we shall be fruitful in the land.', pt: 'E partiu dali e cavou outro poço; e por este não contenderam; e chamou o seu nome Reobote; e disse: Porque agora o Senhor nos fez lugar, e frutificaremos nesta terra.' },
    { v: 23, en: 'And he went up from thence to Beersheba.', pt: 'E subiu dali a Berseba.' },
    { v: 24, en: 'And the LORD appeared unto him the same night, and said, I am the God of Abraham thy father: fear not, for I am with thee, and will bless thee, and multiply thy seed for my servant Abraham\'s sake.', pt: 'E o Senhor apareceu a ele naquela mesma noite e disse: Eu sou o Deus de Abraão, teu pai; não temas, porque eu sou contigo, e te abençoarei e multiplicarei a tua descendência por amor de Abraão, meu servo.' },
    { v: 25, en: 'And he builded an altar there, and called upon the name of the LORD, and pitched his tent there: and there Isaac\'s servants digged a well.', pt: 'E edificou ali um altar, e invocou o nome do Senhor, e armou ali a sua tenda; e os servos de Isaque cavaram ali um poço.' },
    { v: 26, en: 'Then Abimelech went to him from Gerar, and Ahuzzath one of his friends, and Phichol the chief captain of his army.', pt: 'E foi ter com ele Abimeleque de Gerar, e Acuzate, seu amigo, e Ficol, o capitão do seu exército.' },
    { v: 27, en: 'And Isaac said unto them, Wherefore come ye to me, seeing ye hate me, and have sent me away from you?', pt: 'E disse-lhes Isaque: Por que vindes a mim, visto que me odeiais e me mandastes embora de entre vós?' },
    { v: 28, en: 'And they said, We saw certainly that the LORD was with thee: and we said, Let there be now an oath betwixt us, even betwixt us and thee, and let us make a covenant with thee.', pt: 'E eles disseram: Claramente vimos que o Senhor era contigo; e dissemos: Haja agora um juramento entre nós, entre nós e ti, e façamos uma aliança contigo.' },
    { v: 29, en: 'That thou wilt do us no hurt, as we have not touched thee, and as we have done unto thee nothing but good, and have sent thee away in peace: thou art now the blessed of the LORD.', pt: 'Que não nos farás mal, assim como nós não te tocamos, e assim como só te fizemos bem, e te deixamos ir em paz; tu és agora bendito do Senhor.' },
    { v: 30, en: 'And he made them a feast, and they did eat and drink.', pt: 'E ele lhes fez um banquete, e eles comeram e beberam.' },
    { v: 31, en: 'And they rose up betimes in the morning, and sware one to another: and Isaac sent them away, and they departed from him in peace.', pt: 'E levantaram-se de madrugada e juraram um ao outro; e Isaque os despediu, e eles se foram dele em paz.' },
    { v: 32, en: 'And it came to pass the same day, that Isaac\'s servants came, and told him concerning the well which they had digged, and said unto him, We have found water.', pt: 'E aconteceu naquele mesmo dia que os servos de Isaque vieram e lhe contaram acerca do poço que cavaram, e disseram-lhe: Achamos água.' },
    { v: 33, en: 'And he called it Shebah: therefore the name of the city is Beersheba unto this day.', pt: 'E chamou-o Sibá; por isso o nome da cidade é Berseba até ao dia de hoje.' },
    { v: 34, en: 'And Esau was forty years old when he took to wife Judith the daughter of Beeri the Hittite, and Bashemath the daughter of Elon the Hittite.', pt: 'E quando Esaú tinha quarenta anos, tomou por mulher a Judite, filha de Beeri, o heteu, e a Basemate, filha de Elom, o heteu.' },
    { v: 35, en: 'Which were a grief of mind unto Isaac and to Rebekah.', pt: 'E elas foram amargura de espírito para Isaque e para Rebeca.' },
  ],
  27: [
    { v: 1, en: 'And it came to pass, that when Isaac was old, and his eyes were dim, so that he could not see, he called Esau his eldest son, and said unto him, My son: and he said unto him, Behold, here am I.', pt: 'E aconteceu que, quando Isaque era velho e os seus olhos estavam fracos, de modo que não podia ver, chamou Esaú, seu filho mais velho, e disse-lhe: Meu filho. E ele disse-lhe: Eis-me aqui.' },
    { v: 2, en: 'And he said, Behold now, I am old, I know not the day of my death.', pt: 'E ele disse: Eis que sou velho e não sei o dia da minha morte.' },
    { v: 3, en: 'Now therefore take, I pray thee, thy weapons, thy quiver and thy bow, and go out to the field, and take me some venison.', pt: 'Pega, pois, agora as tuas armas, a tua aljava e o teu arco, e vai ao campo, e caça-me uma caça.' },
    { v: 4, en: 'And make me savoury meat, such as I love, and bring it to me, that I may eat; that my soul may bless thee before I die.', pt: 'E prepara-me uma iguaria saborosa como eu gosto, e traze-ma, para que coma; para que a minha alma te abençoe antes que eu morra.' },
    { v: 5, en: 'And Rebekah heard when Isaac spake to Esau his son. And Esau went to the field to hunt for venison, and to bring it.', pt: 'E Rebeca ouviu quando Isaque falava a Esaú, seu filho. E Esaú foi ao campo para caçar e trazer.' },
    { v: 6, en: 'And Rebekah spake unto Jacob her son, saying, Behold, I heard thy father speak unto Esau thy brother, saying.', pt: 'E Rebeca falou a Jacó, seu filho, dizendo: Eis que ouvi teu pai falar a Esaú, teu irmão, dizendo.' },
    { v: 7, en: 'Bring me venison, and make me savoury meat, that I may eat, and bless thee before the LORD before my death.', pt: 'Traze-me caça e prepara-me uma iguaria saborosa, para que eu coma, e te abençoe perante o Senhor antes da minha morte.' },
    { v: 8, en: 'Now therefore, my son, obey my voice according to that which I command thee.', pt: 'Agora, pois, meu filho, obedece à minha voz naquilo que te ordeno.' },
    { v: 9, en: 'Go now to the flock, and fetch me from thence two good kids of the goats; and I will make them savoury meat for thy father, such as he loveth.', pt: 'Vai agora ao rebanho, e toma-me de lá dois cabritos bons; e prepararei deles uma iguaria saborosa para teu pai, como ele gosta.' },
    { v: 10, en: 'And thou shalt bring it to thy father, that he may eat, and that he may bless thee before his death.', pt: 'E tu a levarás a teu pai, para que ele coma, e te abençoe antes da sua morte.' },
    { v: 11, en: 'And Jacob said to Rebekah his mother, Behold, Esau my brother is a hairy man, and I am a smooth man.', pt: 'E disse Jacó a Rebeca, sua mãe: Eis que Esaú, meu irmão, é homem peludo, e eu sou homem liso.' },
    { v: 12, en: 'My father peradventure will feel me, and I shall seem to him as a deceiver; and I shall bring a curse upon me, and not a blessing.', pt: 'Porventura meu pai me apalpará, e serei aos seus olhos como enganador; e trarei sobre mim maldição, e não bênção.' },
    { v: 13, en: 'And his mother said unto him, Upon me be thy curse, my son: only obey my voice, and go fetch me them.', pt: 'E sua mãe disse-lhe: Sobre mim seja a tua maldição, meu filho; somente obedece à minha voz e vai buscá-los.' },
    { v: 14, en: 'And he went, and fetched, and brought them to his mother: and his mother made savoury meat, such as his father loved.', pt: 'E ele foi e os tomou e os trouxe a sua mãe; e sua mãe preparou uma iguaria saborosa como seu pai gostava.' },
    { v: 15, en: 'And Rebekah took goodly raiment of her eldest son Esau, which were with her in the house, and put them upon Jacob her younger son.', pt: 'E Rebeca tomou os melhores vestidos de Esaú, seu filho mais velho, que ela tinha em casa, e os pôs sobre Jacó, seu filho mais novo.' },
    { v: 16, en: 'And she put the skins of the kids of the goats upon his hands, and upon the smooth of his neck.', pt: 'E cobriu as suas mãos e a parte lisa do seu pescoço com as peles dos cabritos.' },
    { v: 17, en: 'And she gave the savoury meat and the bread, which she had prepared, into the hand of her son Jacob.', pt: 'E pôs a iguaria saborosa e o pão que havia preparado na mão de Jacó, seu filho.' },
    { v: 18, en: 'And he came unto his father, and said, My father: and he said, Here am I; who art thou, my son?', pt: 'E ele foi a seu pai e disse: Meu pai. E ele disse: Eis-me aqui; quem és tu, meu filho?' },
    { v: 19, en: 'And Jacob said unto his father, I am Esau thy first born; I have done according as thou badest me: arise, I pray thee, sit and eat of my venison, that thy soul may bless me.', pt: 'E disse Jacó a seu pai: Sou Esaú, teu primogênito; fiz como me disseste; levanta-te, peço-te, assenta-te e come da minha caça, para que a tua alma me abençoe.' },
    { v: 20, en: 'And Isaac said unto his son, How is it that thou hast found it so quickly, my son? And he said, Because the LORD thy God brought it to chance before me.', pt: 'E disse Isaque a seu filho: Como é que a achaste tão depressa, meu filho? E ele disse: Porque o Senhor, teu Deus, a trouxe diante de mim.' },
    { v: 21, en: 'And Isaac said unto Jacob, Come near, I pray thee, that I may feel thee, my son, whether thou be my very son Esau or not.', pt: 'E disse Isaque a Jacó: Chega-te, peço-te, para que te apalpe, meu filho, para saber se és mesmo meu filho Esaú, ou não.' },
    { v: 22, en: 'And Jacob went near unto Isaac his father; and he felt him, and said, The voice is Jacob\'s voice, but the hands are the hands of Esau.', pt: 'E Jacó se chegou a Isaque, seu pai; e ele o apalpou e disse: A voz é a voz de Jacó, mas as mãos são as mãos de Esaú.' },
    { v: 23, en: 'And he discerned him not, because his hands were hairy, as his brother Esau\'s hands: so he blessed him.', pt: 'E não o conheceu, porque as suas mãos eram peludas como as mãos de Esaú, seu irmão; e o abençoou.' },
    { v: 24, en: 'And he said, Art thou my very son Esau? And he said, I am.', pt: 'E disse: És mesmo meu filho Esaú? E ele disse: Sou.' },
    { v: 25, en: 'And he said, Bring it near to me, and I will eat of my son\'s venison, that my soul may bless thee. And he brought it near to him, and he did eat: and he brought him wine, and he drank.', pt: 'E disse: Traze-a a mim, e comerei da caça do meu filho, para que a minha alma te abençoe. E trouxe-lha, e ele comeu; e trouxe-lhe vinho, e bebeu.' },
    { v: 26, en: 'And his father Isaac said unto him, Come near now, and kiss me, my son.', pt: 'E disse-lhe Isaque, seu pai: Chega-te agora e beija-me, meu filho.' },
    { v: 27, en: 'And he came near, and kissed him: and he smelled the smell of his raiment, and blessed him, and said, See, the smell of my son is as the smell of a field which the LORD hath blessed.', pt: 'E ele se chegou e o beijou; e sentiu o cheiro dos seus vestidos, e o abençoou e disse: Veja, o cheiro do meu filho é como o cheiro de um campo que o Senhor abençoou.' },
    { v: 28, en: 'Therefore God give thee of the dew of heaven, and the fatness of the earth, and plenty of corn and wine.', pt: 'Deus te dê, pois, do orvalho do céu e da gordura da terra, e abundância de trigo e de vinho.' },
    { v: 29, en: 'Let people serve thee, and nations bow down to thee: be lord over thy brethren, and let thy mother\'s sons bow down to thee: cursed be every one that curseth thee, and blessed be he that blesseth thee.', pt: 'Sirvam-te os povos, e dobrem-se a ti as nações; sê senhor sobre os teus irmãos, e os filhos de tua mãe se inclinaram a ti; maldito seja quem te amaldiçoar, e bendito quem te abençoar.' },
    { v: 30, en: 'And it came to pass, as soon as Isaac had made an end of blessing Jacob, and Jacob was yet scarce gone out from the presence of Isaac his father, that Esau his brother came in from his hunting.', pt: 'E aconteceu que, mal Isaque tinha acabado de abençoar Jacó, e Jacó havia apenas saído da presença de Isaque, seu pai, que Esaú, seu irmão, veio da sua caça.' },
    { v: 31, en: 'And he also had made savoury meat, and brought it unto his father, and said unto his father, Let my father arise, and eat of his son\'s venison, that thy soul may bless me.', pt: 'E ele também preparou uma iguaria saborosa, e a trouxe a seu pai, e disse a seu pai: Levante-se meu pai e coma da caça do seu filho, para que a tua alma me abençoe.' },
    { v: 32, en: 'And Isaac his father said unto him, Who art thou? And he said, I am thy son, thy firstborn Esau.', pt: 'E Isaque, seu pai, disse-lhe: Quem és tu? E ele disse: Sou teu filho, o teu primogênito Esaú.' },
    { v: 33, en: 'And Isaac trembled very exceedingly, and said, Who? where is he that hath taken venison, and brought it me, and I have eaten of all before thou camest, and have blessed him? yea, and he shall be blessed.', pt: 'E Isaque estremeceu muito e disse: Quem é então aquele que caçou a caça e ma trouxe, e eu comi de tudo antes de tu vires, e o abençoei? Sim, e será bendito.' },
    { v: 34, en: 'And when Esau heard the words of his father, he cried with a great and exceeding bitter cry, and said unto his father, Bless me, even me also, O my father.', pt: 'E quando Esaú ouviu as palavras de seu pai, levantou um clamor grande e mui amargo, e disse a seu pai: Abençoa-me também a mim, meu pai.' },
    { v: 35, en: 'And he said, Thy brother came with subtilty, and hath taken away thy blessing.', pt: 'E ele disse: Veio teu irmão com astúcia, e tomou a tua bênção.' },
    { v: 36, en: 'And he said, Is not he rightly named Jacob? for he hath supplanted me these two times: he took away my birthright; and, behold, now he hath taken away my blessing. And he said, Hast thou not reserved a blessing for me?', pt: 'E disse: Não é por isso que se chamou o seu nome Jacó? Porque já por duas vezes me enganou; levou-me a minha primogenitura, e eis que agora tomou a minha bênção. E disse: Não reservaste uma bênção para mim?' },
    { v: 37, en: 'And Isaac answered and said unto Esau, Behold, I have made him thy lord, and all his brethren have I given to him for servants; and with corn and wine have I sustained him: and what shall I do now unto thee, my son?', pt: 'E respondeu Isaque e disse a Esaú: Eis que o pus por senhor teu, e todos os seus irmãos lhe dei por servos; e de trigo e de vinho o sustentei; e agora o que farei a ti, meu filho?' },
    { v: 38, en: 'And Esau said unto his father, Hast thou but one blessing, my father? bless me, even me also, O my father. And Esau lifted up his voice, and wept.', pt: 'E disse Esaú a seu pai: Só tens uma bênção, meu pai? Abençoa-me também a mim, meu pai. E Esaú levantou a sua voz e chorou.' },
    { v: 39, en: 'And Isaac his father answered and said unto him, Behold, thy dwelling shall be the fatness of the earth, and of the dew of heaven from above.', pt: 'E respondeu Isaque, seu pai, e disse-lhe: Eis que a tua habitação será da gordura da terra e do orvalho do céu lá de cima.' },
    { v: 40, en: 'And by thy sword shalt thou live, and shalt serve thy brother; and it shall come to pass when thou shalt have the dominion, that thou shalt break his yoke from off thy neck.', pt: 'E pela tua espada viverás, e ao teu irmão servirás; mas acontecerá que quando te libertares, sacudirás o seu jugo do teu pescoço.' },
    { v: 41, en: 'And Esau hated Jacob because of the blessing wherewith his father blessed him: and Esau said in his heart, The days of mourning for my father are at hand; then will I slay my brother Jacob.', pt: 'E Esaú odiou a Jacó por causa da bênção com que seu pai o havia abençoado; e Esaú disse no seu coração: Aproximam-se os dias do pranto por meu pai; então matarei a Jacó, meu irmão.' },
    { v: 42, en: 'And these words of Esau her elder son were told to Rebekah: and she sent and called Jacob her younger son, and said unto him, Behold, thy brother Esau, as touching thee, doth comfort himself, purposing to kill thee.', pt: 'E as palavras de Esaú, seu filho mais velho, foram anunciadas a Rebeca; e ela mandou chamar Jacó, seu filho mais novo, e disse-lhe: Eis que Esaú, teu irmão, consola-se a teu respeito, tencionando matar-te.' },
    { v: 43, en: 'Now therefore, my son, obey my voice; and arise, flee thou to Laban my brother to Haran.', pt: 'Agora, pois, meu filho, obedece à minha voz; levanta-te, foge para Labão, meu irmão, a Harã.' },
    { v: 44, en: 'And tarry with him a few days, until thy brother\'s fury turn away.', pt: 'E fica com ele alguns dias, até que o furor de teu irmão se apazigue.' },
    { v: 45, en: 'Until thy brother\'s anger turn away from thee, and he forget that which thou hast done to him: then I will send, and fetch thee from thence: why should I be deprived also of you both in one day?', pt: 'Até que a ira de teu irmão se aparte de ti, e ele se esqueça do que lhe fizeste; então mandarei buscar-te de lá; por que hei de ser privada de vós dois num dia?' },
    { v: 46, en: 'And Rebekah said to Isaac, I am weary of my life because of the daughters of Heth: if Jacob take a wife of the daughters of Heth, such as these which are of the daughters of the land, what good shall my life do me?', pt: 'E disse Rebeca a Isaque: Estou enojada da minha vida por causa das filhas de Hete; se Jacó tomar uma mulher das filhas de Hete, como estas, das filhas desta terra, de que me servirá a vida?' },
  ],
  28: [
    { v: 1, en: 'And Isaac called Jacob, and blessed him, and charged him, and said unto him, Thou shalt not take a wife of the daughters of Canaan.', pt: 'E chamou Isaque a Jacó, e o abençoou, e lhe ordenou, e disse-lhe: Não tomarás mulher das filhas de Canaã.' },
    { v: 2, en: 'Arise, go to Padanaram, to the house of Bethuel thy mother\'s father; and take thee a wife from thence of the daughters of Laban thy mother\'s brother.', pt: 'Levanta-te, vai a Padã-Arã, à casa de Betuel, pai de tua mãe, e toma de lá uma mulher das filhas de Labão, irmão de tua mãe.' },
    { v: 3, en: 'And God Almighty bless thee, and make thee fruitful, and multiply thee, that thou mayest be a multitude of people.', pt: 'E o Deus Todo-poderoso te abençoe, e te faça frutificar e te multiplique, para que venhas a ser uma multidão de povos.' },
    { v: 4, en: 'And give thee the blessing of Abraham, to thee, and to thy seed with thee; that thou mayest inherit the land wherein thou art a stranger, which God gave unto Abraham.', pt: 'E te dê a bênção de Abraão, a ti e à tua descendência contigo, para que herdes a terra de tuas peregrinações, que Deus deu a Abraão.' },
    { v: 5, en: 'And Isaac sent away Jacob: and he went to Padanaram unto Laban, son of Bethuel the Syrian, the brother of Rebekah, Jacob\'s and Esau\'s mother.', pt: 'E Isaque despediu Jacó; e ele foi a Padã-Arã, a Labão, filho de Betuel, o arameu, irmão de Rebeca, mãe de Jacó e de Esaú.' },
    { v: 6, en: 'When Esau saw that Isaac had blessed Jacob, and sent him away to Padanaram, to take him a wife from thence; and that as he blessed him he gave him a charge, saying, Thou shalt not take a wife of the daughters of Canaan.', pt: 'E vendo Esaú que Isaque havia abençoado Jacó e o enviara a Padã-Arã para tomar de lá uma mulher; e que ao abençoá-lo lhe dera uma ordem dizendo: Não tomarás mulher das filhas de Canaã.' },
    { v: 7, en: 'And that Jacob obeyed his father and his mother, and was gone to Padanaram.', pt: 'E que Jacó havia obedecido a seu pai e a sua mãe, e fora a Padã-Arã.' },
    { v: 8, en: 'And Esau seeing that the daughters of Canaan pleased not Isaac his father.', pt: 'E vendo Esaú que as filhas de Canaã desagradavam a Isaque, seu pai.' },
    { v: 9, en: 'Then went Esau unto Ishmael, and took unto the wives which he had Mahalath the daughter of Ishmael Abraham\'s son, the sister of Nebajoth, to be his wife.', pt: 'Foi Esaú a Ismael, e tomou além das mulheres que tinha, por mulher, a Maaalate, filha de Ismael, filho de Abraão, irmã de Nebaiote.' },
    { v: 10, en: 'And Jacob went out from Beersheba, and went toward Haran.', pt: 'E partiu Jacó de Berseba e foi para Harã.' },
    { v: 11, en: 'And he lighted upon a certain place, and tarried there all night, because the sun was set; and he took of the stones of that place, and put them for his pillows, and lay down in that place to sleep.', pt: 'E chegou a um certo lugar, e ficou ali a noite, porque o sol já se havia posto; e tomou uma das pedras daquele lugar, e a pôs por travesseiro, e se deitou naquele lugar para dormir.' },
    { v: 12, en: 'And he dreamed, and behold a ladder set up on the earth, and the top of it reached to heaven: and behold the angels of God ascending and descending on it.', pt: 'E sonhou; e eis uma escada posta na terra, cujo topo tocava nos céus; e eis os anjos de Deus subindo e descendo por ela.' },
    { v: 13, en: 'And, behold, the LORD stood above it, and said, I am the LORD God of Abraham thy father, and the God of Isaac: the land whereon thou liest, to thee will I give it, and to thy seed.', pt: 'E eis o Senhor estava encima dela, e disse: Eu sou o Senhor, o Deus de Abraão, teu pai, e o Deus de Isaque; esta terra em que estás deitado, ta darei a ti e à tua descendência.' },
    { v: 14, en: 'And thy seed shall be as the dust of the earth, and thou shalt spread abroad to the west, and to the east, and to the north, and to the south: and in thee and in thy seed shall all the families of the earth be blessed.', pt: 'E a tua descendência será como o pó da terra, e te estenderás para o ocidente, e para o oriente, e para o norte, e para o sul; e em ti e na tua descendência serão benditas todas as famílias da terra.' },
    { v: 15, en: 'And, behold, I am with thee, and will keep thee in all places whither thou goest, and will bring thee again into this land; for I will not leave thee, until I have done that which I have spoken to thee of.', pt: 'E eis que sou contigo, e te guardarei em todos os lugares para onde fores, e te farei voltar a esta terra; porque não te deixarei até que haja feito o que te disse.' },
    { v: 16, en: 'And Jacob awaked out of his sleep, and he said, Surely the LORD is in this place; and I knew it not.', pt: 'E Jacó despertou do seu sono e disse: Verdadeiramente o Senhor está neste lugar, e eu não sabia.' },
    { v: 17, en: 'And he was afraid, and said, How dreadful is this place! this is none other but the house of God, and this is the gate of heaven.', pt: 'E teve medo e disse: Quão temível é este lugar! Esta não é senão a casa de Deus, e esta é a porta dos céus.' },
    { v: 18, en: 'And Jacob rose up early in the morning, and took the stone that he had put for his pillows, and set it up for a pillar, and poured oil upon the top of it.', pt: 'E Jacó se levantou de madrugada, e tomou a pedra que havia posto por travesseiro, e a erigiu como coluna, e derramou azeite no topo dela.' },
    { v: 19, en: 'And he called the name of that place Bethel: but the name of that city was called Luz at the first.', pt: 'E chamou o nome daquele lugar Betel; contudo o nome daquela cidade chamava-se antes Luz.' },
    { v: 20, en: 'And Jacob vowed a vow, saying, If God will be with me, and will keep me in this way that I go, and will give me bread to eat, and raiment to put on.', pt: 'E Jacó fez um voto, dizendo: Se Deus for comigo e me guardar neste caminho que percorro, e me der pão para comer e vestido para vestir.' },
    { v: 21, en: 'So that I come again to my father\'s house in peace; then shall the LORD be my God.', pt: 'E eu voltar em paz à casa de meu pai, então o Senhor será o meu Deus.' },
    { v: 22, en: 'And this stone, which I have set for a pillar, shall be God\'s house: and of all that thou shalt give me I will surely give the tenth unto thee.', pt: 'E esta pedra que eigi por coluna será a casa de Deus; e de tudo o que me deres, certamente te darei o dízimo.' },
  ],
  29: [
    { v: 1, en: 'Then Jacob went on his journey, and came into the land of the people of the east.', pt: 'E Jacó continuou a sua viagem e foi à terra dos filhos do oriente.' },
    { v: 2, en: 'And he looked, and behold a well in the field, and, lo, there were three flocks of sheep lying by it; for out of that well they watered the flocks: and a great stone was upon the well\'s mouth.', pt: 'E olhou, e eis um poço no campo; e eis três rebanhos de ovelhas que se deitavam junto a ele; porque daquele poço davam de beber aos rebanhos; e havia uma grande pedra sobre a boca do poço.' },
    { v: 3, en: 'And thither were all the flocks gathered: and they rolled the stone from the well\'s mouth, and watered the sheep, and put the stone again upon the well\'s mouth in his place.', pt: 'E todos os rebanhos se ajuntavam ali; e revolviam a pedra da boca do poço, e davam de beber às ovelhas, e tornavam a pôr a pedra sobre a boca do poço no seu lugar.' },
    { v: 4, en: 'And Jacob said unto them, My brethren, whence be ye? And they said, Of Haran are we.', pt: 'E disse-lhes Jacó: Meus irmãos, donde sois? E eles disseram: Somos de Harã.' },
    { v: 5, en: 'And he said unto them, Know ye Laban the son of Nahor? And they said, We know him.', pt: 'E ele disse-lhes: Conheceis a Labão, filho de Naor? E disseram: Conhecemos.' },
    { v: 6, en: 'And he said unto them, Is he well? And they said, He is well: and, behold, Rachel his daughter cometh with the sheep.', pt: 'E ele disse-lhes: Está ele bem? E disseram: Está bem; e eis que Raquel, sua filha, vem com as ovelhas.' },
    { v: 7, en: 'And he said, Lo, it is yet high day, neither is it time that the cattle should be gathered together: water ye the sheep, and go and feed them.', pt: 'E ele disse: Ainda é pleno dia; não é ainda tempo de ajuntar o gado; dai de beber às ovelhas e ide apascentá-las.' },
    { v: 8, en: 'And they said, We cannot, until all the flocks be gathered together, and till they roll the stone from the well\'s mouth; then we water the sheep.', pt: 'E eles disseram: Não podemos, até que todos os rebanhos se juntem e revolva a pedra da boca do poço; então daremos de beber às ovelhas.' },
    { v: 9, en: 'And while he yet spake with them, Rachel came with her father\'s sheep: for she kept them.', pt: 'Enquanto ainda falava com eles, veio Raquel com as ovelhas de seu pai; porque ela as pastoreava.' },
    { v: 10, en: 'And it came to pass, when Jacob saw Rachel the daughter of Laban his mother\'s brother, and the sheep of Laban his mother\'s brother, that Jacob went near, and rolled the stone from the well\'s mouth, and watered the flock of Laban his mother\'s brother.', pt: 'E aconteceu que, quando Jacó viu Raquel, filha de Labão, irmão de sua mãe, e as ovelhas de Labão, irmão de sua mãe, Jacó chegou e revolveu a pedra da boca do poço, e deu de beber ao rebanho de Labão, irmão de sua mãe.' },
    { v: 11, en: 'And Jacob kissed Rachel, and lifted up his voice, and wept.', pt: 'E Jacó beijou Raquel e levantou a sua voz e chorou.' },
    { v: 12, en: 'And Jacob told Rachel that he was her father\'s brother, and that he was Rebekah\'s son: and she ran and told her father.', pt: 'E Jacó contou a Raquel que era irmão de seu pai, e que era filho de Rebeca; e ela correu e contou a seu pai.' },
    { v: 13, en: 'And it came to pass, when Laban heard the tidings of Jacob his sister\'s son, that he ran to meet him, and embraced him, and kissed him, and brought him to his house. And he told Laban all these things.', pt: 'E aconteceu que, quando Labão ouviu as novas de Jacó, filho de sua irmã, correu ao seu encontro, abraçou-o e beijou-o, e o trouxe a sua casa. E Jacó contou a Labão todas estas coisas.' },
    { v: 14, en: 'And Laban said to him, Surely thou art my bone and my flesh. And he abode with him the space of a month.', pt: 'E disse-lhe Labão: Certamente és o meu osso e a minha carne. E ficou com ele um mês inteiro.' },
    { v: 15, en: 'And Laban said unto Jacob, Because thou art my brother, shouldest thou therefore serve me for nought? tell me, what shall thy wages be?', pt: 'E disse Labão a Jacó: Porque és meu irmão, hás de servir-me de graça? Dize-me qual será o teu salário.' },
    { v: 16, en: 'And Laban had two daughters: the name of the elder was Leah, and the name of the younger was Rachel.', pt: 'E Labão tinha duas filhas; o nome da mais velha era Lia, e o nome da mais nova era Raquel.' },
    { v: 17, en: 'Leah was tender eyed; but Rachel was beautiful and well favoured.', pt: 'E os olhos de Lia eram fracos; mas Raquel era formosa de semblante e bela de aparência.' },
    { v: 18, en: 'And Jacob loved Rachel; and said, I will serve thee seven years for Rachel thy younger daughter.', pt: 'E Jacó amava a Raquel; e disse: Servir-te-ei sete anos por Raquel, tua filha mais nova.' },
    { v: 19, en: 'And Laban said, It is better that I give her to thee, than that I should give her to another man: abide with me.', pt: 'E disse Labão: Melhor é que eu ta dê a ti do que a outro homem; fica comigo.' },
    { v: 20, en: 'And Jacob served seven years for Rachel; and they seemed unto him but a few days, for the love he had to her.', pt: 'E serviu Jacó sete anos por Raquel; e pareceram-lhe como poucos dias, por amor que lhe tinha.' },
    { v: 21, en: 'And Jacob said unto Laban, Give me my wife, for my days are fulfilled, that I may go in unto her.', pt: 'E disse Jacó a Labão: Dá-me a minha mulher, porque os meus dias já se cumpriram, para que me chegue a ela.' },
    { v: 22, en: 'And Laban gathered together all the men of the place, and made a feast.', pt: 'E Labão ajuntou todos os homens do lugar e fez um banquete.' },
    { v: 23, en: 'And it came to pass in the evening, that he took Leah his daughter, and brought her to him; and he went in unto her.', pt: 'E aconteceu que à tarde tomou Lia, sua filha, e a trouxe a ele; e ele se chegou a ela.' },
    { v: 24, en: 'And Laban gave unto his daughter Leah Zilpah his maid for an handmaid.', pt: 'E Labão deu à sua filha Lia, Zilpa, sua serva, por serva.' },
    { v: 25, en: 'And it came to pass, that in the morning, behold, it was Leah: and he said to Laban, What is this thou hast done unto me? did not I serve with thee for Rachel? wherefore then hast thou beguiled me?', pt: 'E aconteceu que pela manhã, eis que era Lia; e disse a Labão: Que é isto que me fizeste? Não te servi por Raquel? Por que então me enganaste?' },
    { v: 26, en: 'And Laban said, It must not be so done in our country, to give the younger before the firstborn.', pt: 'E disse Labão: Não se faz assim em nosso lugar, dar a mais nova antes da primogênita.' },
    { v: 27, en: 'Fulfil her week, and we will give thee this also for the service which thou shalt serve with me yet seven other years.', pt: 'Cumpre a semana desta, e te daremos também aquela pelo serviço que ainda servirás comigo outros sete anos.' },
    { v: 28, en: 'And Jacob did so, and fulfilled her week: and he gave him Rachel his daughter to wife also.', pt: 'E Jacó fez assim, e cumpriu a semana dela; e ele lhe deu Raquel, sua filha, por mulher.' },
    { v: 29, en: 'And Laban gave to Rachel his daughter Bilhah his handmaid to be her maid.', pt: 'E Labão deu à sua filha Raquel, Bila, sua serva, por serva.' },
    { v: 30, en: 'And he went in also unto Rachel, and he loved also Rachel more than Leah, and served with him yet seven other years.', pt: 'E ele se chegou também a Raquel, e amou também a Raquel mais do que a Lia; e serviu com ele ainda outros sete anos.' },
    { v: 31, en: 'And when the LORD saw that Leah was hated, he opened her womb: but Rachel was barren.', pt: 'E vendo o Senhor que Lia era preterida, abriu-lhe a madre; mas Raquel era estéril.' },
    { v: 32, en: 'And Leah conceived, and bare a son, and she called his name Reuben: for she said, Surely the LORD hath looked upon my affliction; now therefore my husband will love me.', pt: 'E Lia concebeu e deu à luz um filho, e chamou o seu nome Rúben; porque disse: O Senhor atentou para a minha aflição; agora, pois, meu marido me amará.' },
    { v: 33, en: 'And she conceived again, and bare a son; and said, Because the LORD hath heard that I was hated, he hath therefore given me this son also: and she called his name Simeon.', pt: 'E concebeu outra vez e deu à luz um filho, e disse: Porque o Senhor ouviu que eu era preterida, deu-me também este. E chamou o seu nome Simeão.' },
    { v: 34, en: 'And she conceived again, and bare a son; and said, Now this time will my husband be joined unto me, because I have born him three sons: therefore was his name called Levi.', pt: 'E tornou a conceber e deu à luz um filho, e disse: Desta vez se unirá meu marido a mim, porque lhe dei três filhos; por isso chamou o seu nome Levi.' },
    { v: 35, en: 'And she conceived again, and bare a son: and she said, Now will I praise the LORD: therefore she called his name Judah; and left bearing.', pt: 'E tornou a conceber e deu à luz um filho; e disse: Esta vez louvarei o Senhor; por isso chamou o seu nome Judá; e cessou de dar à luz.' },
  ],
  30: [
    { v: 1, en: 'And when Rachel saw that she bare Jacob no children, Rachel envied her sister; and said unto Jacob, Give me children, or else I die.', pt: 'E vendo Raquel que não dava filhos a Jacó, teve Raquel inveja de sua irmã; e disse a Jacó: Dá-me filhos; do contrário morrerei.' },
    { v: 2, en: 'And Jacob\'s anger was kindled against Rachel: and he said, Am I in God\'s stead, who hath withheld from thee the fruit of the womb?', pt: 'E acendeu-se a ira de Jacó contra Raquel, e disse: Estou eu em lugar de Deus, que te vedou o fruto do ventre?' },
    { v: 3, en: 'And she said, Behold my maid Bilhah, go in unto her; and she shall bear upon my knees, that I may also have children by her.', pt: 'E ela disse: Eis aqui a minha serva Bila; chegues a ela, para que dê à luz sobre os meus joelhos, e eu assim tenha filhos por ela.' },
    { v: 4, en: 'And she gave him Bilhah her handmaid to wife: and Jacob went in unto her.', pt: 'E deu-lhe Bila, sua serva, por mulher; e Jacó se chegou a ela.' },
    { v: 5, en: 'And Bilhah conceived, and bare Jacob a son.', pt: 'E Bila concebeu e deu a Jacó um filho.' },
    { v: 6, en: 'And Rachel said, God hath judged me, and hath also heard my voice, and hath given me a son: therefore called she his name Dan.', pt: 'E disse Raquel: Deus me fez justiça, e também ouviu a minha voz e me deu um filho; por isso chamou o seu nome Dã.' },
    { v: 7, en: 'And Bilhah Rachel\'s maid conceived again, and bare Jacob a second son.', pt: 'E Bila, serva de Raquel, concebeu outra vez e deu a Jacó um segundo filho.' },
    { v: 8, en: 'And Rachel said, With great wrestlings have I wrestled with my sister, and I have prevailed: and she called his name Naphtali.', pt: 'E disse Raquel: Com grandes lutas lutei com minha irmã, e prevaleci; e chamou o seu nome Naftali.' },
    { v: 9, en: 'When Leah saw that she had left bearing, she took Zilpah her maid, and gave her Jacob to wife.', pt: 'E vendo Lia que havia cessado de dar à luz, tomou Zilpa, sua serva, e a deu a Jacó por mulher.' },
    { v: 10, en: 'And Zilpah Leah\'s maid bare Jacob a son.', pt: 'E Zilpa, serva de Lia, deu a Jacó um filho.' },
    { v: 11, en: 'And Leah said, A troop cometh: and she called his name Gad.', pt: 'E disse Lia: Felizmente! E chamou o seu nome Gade.' },
    { v: 12, en: 'And Zilpah Leah\'s maid bare Jacob a second son.', pt: 'E Zilpa, serva de Lia, deu a Jacó um segundo filho.' },
    { v: 13, en: 'And Leah said, Happy am I, for the daughters will call me blessed: and she called his name Asher.', pt: 'E disse Lia: Bem-aventurada sou; porque as filhas me chamarão bem-aventurada. E chamou o seu nome Aser.' },
    { v: 14, en: 'And Reuben went in the days of wheat harvest, and found mandrakes in the field, and brought them unto his mother Leah. Then Rachel said to Leah, Give me, I pray thee, of thy son\'s mandrakes.', pt: 'E Rúben foi no tempo da colheita do trigo, e achou mandrágoras no campo, e as trouxe a Lia, sua mãe. E disse Raquel a Lia: Dá-me, peço-te, das mandrágoras de teu filho.' },
    { v: 15, en: 'And she said unto her, Is it a small matter that thou hast taken my husband? and wouldest thou take away my son\'s mandrakes also? And Rachel said, Therefore he shall lie with thee to night for thy son\'s mandrakes.', pt: 'E ela disse: É pouco teres tomado meu marido, que ainda queres tomar as mandrágoras do meu filho? E disse Raquel: Por isso dormirá contigo esta noite pelas mandrágoras do teu filho.' },
    { v: 16, en: 'And Jacob came out of the field in the evening, and Leah went out to meet him, and said, Thou must come in unto me; for surely I have hired thee with my son\'s mandrakes. And he lay with her that night.', pt: 'E Jacó veio do campo à tarde, e Lia saiu ao seu encontro, e disse: Virás a mim, porque certamente te aluguei pelas mandrágoras do meu filho. E deitou-se com ela naquela noite.' },
    { v: 17, en: 'And God hearkened unto Leah, and she conceived, and bare Jacob the fifth son.', pt: 'E Deus atendeu a Lia, e ela concebeu e deu a Jacó o quinto filho.' },
    { v: 18, en: 'And Leah said, God hath given me my hire, because I have given my maiden to my husband: and she called his name Issachar.', pt: 'E disse Lia: Deus me deu o meu salário porque dei a minha serva a meu marido. E chamou o seu nome Issacar.' },
    { v: 19, en: 'And Leah conceived again, and bare Jacob the sixth son.', pt: 'E Lia tornou a conceber e deu a Jacó o sexto filho.' },
    { v: 20, en: 'And Leah said, God hath endued me with a good dowry; now will my husband dwell with me, because I have born him six sons: and she called his name Zebulun.', pt: 'E disse Lia: Deus me dotou com um bom dote; desta vez habitará comigo meu marido, porque lhe dei seis filhos. E chamou o seu nome Zebulom.' },
    { v: 21, en: 'And afterwards she bare a daughter, and called her name Dinah.', pt: 'E depois deu à luz uma filha, e chamou o seu nome Diná.' },
    { v: 22, en: 'And God remembered Rachel, and God hearkened to her, and opened her womb.', pt: 'E Deus se lembrou de Raquel, e Deus a atendeu e abriu o seu ventre.' },
    { v: 23, en: 'And she conceived, and bare a son; and said, God hath taken away my reproach.', pt: 'E ela concebeu e deu à luz um filho; e disse: Deus tirou o meu opróbrio.' },
    { v: 24, en: 'And she called his name Joseph; and said, The LORD shall add to me another son.', pt: 'E chamou o seu nome José; e disse: O Senhor me acrescentará outro filho.' },
    { v: 25, en: 'And it came to pass, when Rachel had born Joseph, that Jacob said unto Laban, Send me away, that I may go unto mine own place, and to my country.', pt: 'E aconteceu que, depois de Raquel ter dado à luz a José, disse Jacó a Labão: Manda-me embora, para que eu vá ao meu lugar e à minha terra.' },
    { v: 26, en: 'Give me my wives and my children, for whom I have served thee, and let me go: for thou knowest my service which I have done thee.', pt: 'Dá-me as minhas mulheres e os meus filhos, pelos quais te servi, e deixa-me ir; porque sabes o serviço que te prestei.' },
    { v: 27, en: 'And Laban said unto him, I pray thee, if I have found favour in thine eyes, tarry: for I have learned by experience that the LORD hath blessed me for thy sake.', pt: 'E disse-lhe Labão: Se achei graça aos teus olhos, fica; aprendi por experiência que o Senhor me abençoou por causa de ti.' },
    { v: 28, en: 'And he said, Appoint me thy wages, and I will give it.', pt: 'E disse: Fixa o teu salário, e eu o darei.' },
    { v: 29, en: 'And he said unto him, Thou knowest how I have served thee, and how thy cattle was with me.', pt: 'E ele disse-lhe: Tu sabes como te servi, e como o teu gado foi comigo.' },
    { v: 30, en: 'For it was little which thou hadst before I came, and it is now increased unto a multitude; and the LORD hath blessed thee since my coming: and now when shall I provide for mine own house also?', pt: 'Porque o que tinhas antes que eu viesse era pouco, e agora cresceu em grande maneira; e o Senhor te abençoou desde a minha chegada; e quando providenciarei também para a minha própria casa?' },
    { v: 31, en: 'And he said, What shall I give thee? And Jacob said, Thou shalt not give me any thing: if thou wilt do this thing for me, I will again feed and keep thy flock.', pt: 'E disse: Que te darei? E disse Jacó: Não me darás nada; se me fizeres esta coisa, tornarei a apascentar e guardar o teu rebanho.' },
    { v: 32, en: 'I will pass through all thy flock to day, removing from thence all the speckled and spotted cattle, and all the brown cattle among the sheep, and the spotted and speckled among the goats: and of such shall be my hire.', pt: 'Passarei hoje por todo o teu rebanho, separando dele todo o animal malhado e pintado, e todo o animal escuro entre as ovelhas, e o pintado e malhado entre as cabras; e este será o meu salário.' },
    { v: 33, en: 'So shall my righteousness answer for me in time to come, when it shall come for my hire before thy face: every one that is not speckled and spotted among the goats, and brown among the sheep, that shall be counted stolen with me.', pt: 'E a minha justiça responderá por mim amanhã, quando vieres rever o meu salário; todo animal que não for malhado e pintado entre as cabras, e escuro entre as ovelhas, será tido como furtado por mim.' },
    { v: 34, en: 'And Laban said, Behold, I would it might be according to thy word.', pt: 'E disse Labão: Eis que seja assim como disseste.' },
    { v: 35, en: 'And he removed that day the he goats that were ringstraked and spotted, and all the she goats that were speckled and spotted, and every one that had some white in it, and all the brown among the sheep, and gave them into the hand of his sons.', pt: 'E naquele dia separou os bodes rajados e pintados, e todas as cabras malhadas e pintadas, todo animal que tinha algum branco, e todo o escuro entre as ovelhas, e os entregou nas mãos dos seus filhos.' },
    { v: 36, en: 'And he set three days\' journey betwixt himself and Jacob: and Jacob fed the rest of Laban\'s flocks.', pt: 'E pôs uma distância de três dias de viagem entre si e Jacó; e Jacó apascentava o restante dos rebanhos de Labão.' },
    { v: 37, en: 'And Jacob took him rods of green poplar, and of the hazel and chesnut tree; and pilled white strakes in them, and made the white appear which was in the rods.', pt: 'E tomou Jacó varas verdes de álamo e de amendoeiro e de plátano, e descascou nelas tiras brancas, deixando aparecer a parte branca das varas.' },
    { v: 38, en: 'And he set the rods which he had pilled before the flocks in the gutters in the watering troughs when the flocks came to drink, that they should conceive when they came to drink.', pt: 'E pôs as varas que descascara nos cochos, nas calhas de água, onde os rebanhos vinham beber, em frente dos rebanhos; e eles concebiam quando vinham beber.' },
    { v: 39, en: 'And the flocks conceived before the rods, and brought forth cattle ringstraked, speckled, and spotted.', pt: 'E os rebanhos concebiam diante das varas, e os animais pariam rajados, malhados e pintados.' },
    { v: 40, en: 'And Jacob did separate the lambs, and set the faces of the flocks toward the ringstraked, and all the brown in the flock of Laban; and he put his own flocks by themselves, and put them not unto Laban\'s cattle.', pt: 'E os cordeiros Jacó os separava, e punha os rostos do rebanho em direção aos rajados e a todo o escuro do rebanho de Labão; e punha o seu rebanho separado, e não o misturava com o gado de Labão.' },
    { v: 41, en: 'And it came to pass, whensoever the stronger cattle did conceive, that Jacob laid the rods before the eyes of the cattle in the gutters, that they might conceive among the rods.', pt: 'E acontecia que, quando o gado mais forte concebia, Jacó punha as varas diante dos olhos do gado nos cochos, para que concebessem junto às varas.' },
    { v: 42, en: 'But when the cattle were feeble, he put them not in: so the feebler were Laban\'s, and the stronger Jacob\'s.', pt: 'Mas quando o gado era fraco, não as punha; assim os mais fracos eram de Labão, e os mais fortes de Jacó.' },
    { v: 43, en: 'And the man increased exceedingly, and had much cattle, and maidservants, and menservants, and camels, and asses.', pt: 'E o homem se enriqueceu em grande maneira, e tinha muito gado, e servas e servos, e camelos e jumentos.' },
  ],
  31: [
    { v: 1, en: 'And he heard the words of Laban\'s sons, saying, Jacob hath taken away all that was our father\'s; and of that which was our father\'s hath he gotten all this glory.', pt: 'E ouviu as palavras dos filhos de Labão, que diziam: Jacó tomou tudo o que era de nosso pai; e do que era de nosso pai adquiriu toda esta riqueza.' },
    { v: 2, en: 'And Jacob beheld the countenance of Laban, and, behold, it was not toward him as before.', pt: 'E olhou Jacó para o rosto de Labão, e eis que não era para com ele como dantes.' },
    { v: 3, en: 'And the LORD said unto Jacob, Return unto the land of thy fathers, and to thy kindred; and I will be with thee.', pt: 'E disse o Senhor a Jacó: Volta à terra de teus pais e ao teu parentesco; e eu serei contigo.' },
    { v: 4, en: 'And Jacob sent and called Rachel and Leah to the field unto his flock.', pt: 'E Jacó mandou chamar Raquel e Lia ao campo, junto ao seu rebanho.' },
    { v: 5, en: 'And said unto them, I see your father\'s countenance, that it is not toward me as before; but the God of my father hath been with me.', pt: 'E disse-lhes: Vejo que o rosto de vosso pai não é para comigo como dantes; mas o Deus de meu pai era comigo.' },
    { v: 6, en: 'And ye know that with all my power I have served your father.', pt: 'E vós sabeis que servi vosso pai com todas as minhas forças.' },
    { v: 7, en: 'And your father hath deceived me, and changed my wages ten times; but God suffered him not to hurt me.', pt: 'E vosso pai me enganou e mudou o meu salário dez vezes; mas Deus não o deixou fazer-me mal.' },
    { v: 8, en: 'If he said thus, The speckled shall be thy wages; then all the cattle bare speckled: and if he said thus, The ringstraked shall be thy hire; then bare all the cattle ringstraked.', pt: 'Se ele dizia assim: Os malhados serão o teu salário; então todo o gado paria malhados; e se ele dizia: Os rajados serão o teu salário; então todo o gado paria rajados.' },
    { v: 9, en: 'Thus God hath taken away the cattle of your father, and given them to me.', pt: 'E assim Deus tirou o gado de vosso pai e mo deu.' },
    { v: 10, en: 'And it came to pass at the time that the cattle conceived, that I lifted up mine eyes, and saw in a dream, and, behold, the rams which leaped upon the cattle were ringstraked, speckled, and grisled.', pt: 'E aconteceu no tempo em que o gado concebia que eu levantei os meus olhos e vi em sonho; e eis que os carneiros que saltavam sobre o rebanho eram rajados, malhados e pintados.' },
    { v: 11, en: 'And the angel of God spake unto me in a dream, saying, Jacob: And I said, Here am I.', pt: 'E o anjo de Deus me disse em sonho: Jacó! E eu disse: Eis-me aqui.' },
    { v: 12, en: 'And he said, Lift up now thine eyes, and see, all the rams which leap upon the cattle are ringstraked, speckled, and grisled: for I have seen all that Laban doeth unto thee.', pt: 'E ele disse: Levanta os teus olhos e vê; todos os carneiros que saltam sobre o rebanho são rajados, malhados e pintados; porque vi tudo o que Labão te faz.' },
    { v: 13, en: 'I am the God of Bethel, where thou anointedst the pillar, and where thou vowedst a vow unto me: now arise, get thee out from this land, and return unto the land of thy kindred.', pt: 'Eu sou o Deus de Betel, onde ungiste a coluna e onde me fizeste um voto; levanta-te agora, sai desta terra e volta à terra do teu parentesco.' },
    { v: 14, en: 'And Rachel and Leah answered and said unto him, Is there yet any portion or inheritance for us in our father\'s house?', pt: 'E responderam Raquel e Lia e disseram-lhe: Temos nós ainda alguma parte ou herança na casa de nosso pai?' },
    { v: 15, en: 'Are we not counted of him strangers? for he hath sold us, and hath quite devoured also our money.', pt: 'Não nos tem ele por estranhas? Pois nos vendeu, e consumiu também o nosso dinheiro.' },
    { v: 16, en: 'For all the riches which God hath taken from our father, that is ours, and our children\'s: now then, whatsoever God hath said unto thee, do.', pt: 'Porque toda a riqueza que Deus tirou de nosso pai é nossa e de nossos filhos; agora, pois, faze tudo o que Deus te disse.' },
    { v: 17, en: 'Then Jacob rose up, and set his sons and his wives upon camels.', pt: 'Então Jacó se levantou e pôs seus filhos e suas mulheres sobre camelos.' },
    { v: 18, en: 'And he carried away all his cattle, and all his goods which he had gotten, the cattle of his getting, which he had gotten in Padanaram, for to go to Isaac his father in the land of Canaan.', pt: 'E levou todo o seu gado e todos os bens que havia adquirido, o gado de sua propriedade que havia adquirido em Padã-Arã, para ir a Isaque, seu pai, na terra de Canaã.' },
    { v: 19, en: 'And Laban went to shear his sheep: and Rachel had stolen the images that were her father\'s.', pt: 'E Labão havia ido tosquiar as suas ovelhas; e Raquel furtou os ídolos domésticos que eram de seu pai.' },
    { v: 20, en: 'And Jacob stole away unawares to Laban the Syrian, in that he told him not that he fled.', pt: 'E Jacó enganou a Labão, o arameu, não lhe dizendo que fugia.' },
    { v: 21, en: 'So he fled with all that he had; and he rose up, and passed over the river, and set his face toward the mount Gilead.', pt: 'E fugiu com tudo o que tinha; e levantou-se e passou o rio, e foi em direção ao monte Gileade.' },
    { v: 22, en: 'And it was told Laban on the third day that Jacob was fled.', pt: 'E foi anunciado a Labão ao terceiro dia que Jacó havia fugido.' },
    { v: 23, en: 'And he took his brethren with him, and pursued after him seven days\' journey; and they overtook him in the mount Gilead.', pt: 'E ele tomou os seus irmãos consigo, e o perseguiu por sete dias de jornada, e o alcançou no monte Gileade.' },
    { v: 24, en: 'And God came to Laban the Syrian in a dream by night, and said unto him, Take heed that thou speak not to Jacob either good or bad.', pt: 'E Deus veio a Labão, o arameu, em sonho de noite, e disse-lhe: Guarda-te que não fales a Jacó nem bem nem mal.' },
    { v: 25, en: 'Then Laban overtook Jacob. Now Jacob had pitched his tent in the mount: and Laban with his brethren pitched in the mount of Gilead.', pt: 'E Labão alcançou Jacó. Ora, Jacó havia armado a sua tenda no monte; e Labão armou a sua com os seus irmãos no monte Gileade.' },
    { v: 26, en: 'And Laban said to Jacob, What hast thou done, that thou hast stolen away unawares to me, and carried away my daughters, as captives taken with the sword?', pt: 'E disse Labão a Jacó: Que fizeste? Que me enganaste e levaste as minhas filhas como cativas de espada?' },
    { v: 27, en: 'Wherefore didst thou flee away secretly, and steal away from me; and didst not tell me, that I might have sent thee away with mirth, and with songs, with tabret, and with harp?', pt: 'Por que fugiste assim às escondidas e me enganaste, e não me avisaste? Que eu te enviaria com alegria e com cantares, com tamboril e com harpa.' },
    { v: 28, en: 'And hast not suffered me to kiss my sons and my daughters? thou hast now done foolishly in so doing.', pt: 'E não me deixaste beijar meus filhos e minhas filhas. Agora fizeste loucamente.' },
    { v: 29, en: 'It is in the power of my hand to do you hurt: but the God of your father spake unto me yesternight, saying, Take thou heed that thou speak not to Jacob either good or bad.', pt: 'Estava no poder da minha mão fazer-vos mal; mas o Deus de vosso pai me falou ontem à noite, dizendo: Guarda-te que não fales a Jacó nem bem nem mal.' },
    { v: 30, en: 'And now, though thou wouldest needs be gone, because thou sore longedst after thy father\'s house, yet wherefore hast thou stolen my gods?', pt: 'E agora, ainda que fosses embora porque tens grande saudade da casa de teu pai, por que furtaste os meus deuses?' },
    { v: 31, en: 'And Jacob answered and said to Laban, Because I was afraid: for I said, Peradventure thou wouldest take by force thy daughters from me.', pt: 'E respondeu Jacó e disse a Labão: Porque tive medo; pois disse: Porventura me tomarás as tuas filhas à força.' },
    { v: 32, en: 'With whomsoever thou findest thy gods, let him not live: before our brethren discern thou what is thine with me, and take it to thee. For Jacob knew not that Rachel had stolen them.', pt: 'Com quem quer que achares os teus deuses, não viva; perante os nossos irmãos examina o que há teu comigo, e leva-o. Pois Jacó não sabia que Raquel os havia furtado.' },
    { v: 33, en: 'And Laban went into Jacob\'s tent, and into Leah\'s tent, and into the two maidservants\' tents; but he found them not. Then went he out of Leah\'s tent, and entered into Rachel\'s tent.', pt: 'E entrou Labão na tenda de Jacó, e na tenda de Lia, e na tenda das duas servas; mas não os achou. E saiu da tenda de Lia e entrou na tenda de Raquel.' },
    { v: 34, en: 'Now Rachel had taken the images, and put them in the camel\'s furniture, and sat upon them. And Laban searched all the tent, but found them not.', pt: 'Ora, Raquel havia tomado os ídolos e os pusera na albarda do camelo, e se assentara sobre eles. E Labão apalpou toda a tenda, mas não os achou.' },
    { v: 35, en: 'And she said to her father, Let it not displease my lord that I cannot rise up before thee; for the custom of women is upon me. And he searched, but found not the images.', pt: 'E ela disse a seu pai: Não se irrite meu senhor porque não me posso levantar diante de ti; pois estou com o costume das mulheres. E ele procurou, mas não achou os ídolos.' },
    { v: 36, en: 'And Jacob was wroth, and chode with Laban: and Jacob answered and said to Laban, What is my trespass? what is my sin, that thou hast so hotly pursued after me?', pt: 'E Jacó ficou irado e contendeu com Labão; e respondeu Jacó e disse a Labão: Qual é o meu delito? Qual é o meu pecado, que assim ardentemente me perseguiste?' },
    { v: 37, en: 'Whereas thou hast searched all my stuff, what hast thou found of all thy household stuff? set it here before my brethren and thy brethren, that they may judge betwixt us both.', pt: 'Agora que apalpaste todos os meus trastes, que achaste de todos os trastes da tua casa? Ponha-o aqui diante dos meus irmãos e dos teus irmãos, para que julguem entre nós dois.' },
    { v: 38, en: 'This twenty years have I been with thee; thy ewes and thy she goats have not cast their young, and the rams of thy flock have I not eaten.', pt: 'Estes vinte anos estive contigo; as tuas ovelhas e as tuas cabras nunca abortaram, e os carneiros do teu rebanho nunca comi.' },
    { v: 39, en: 'That which was torn of beasts I brought not unto thee; I bare the loss of it; of my hand didst thou require it, whether stolen by day or stolen by night.', pt: 'Não te trouxe animal despedaçado; eu suportava a perda; de minha mão o requeriste, fosse furtado de dia ou furtado de noite.' },
    { v: 40, en: 'Thus I was; in the day the drought consumed me, and the frost by night; and my sleep departed from mine eyes.', pt: 'Assim era eu; de dia o calor me consumia, e o frio de noite; e o meu sono fugia dos meus olhos.' },
    { v: 41, en: 'Thus have I been twenty years in thy house; I served thee fourteen years for thy two daughters, and six years for thy cattle: and thou hast changed my wages ten times.', pt: 'Assim estive eu vinte anos em tua casa; servi-te catorze anos pelas tuas duas filhas, e seis anos pelo teu gado; e mudaste o meu salário dez vezes.' },
    { v: 42, en: 'Except the God of my father, the God of Abraham, and the fear of Isaac, had been with me, surely thou hadst sent me away now empty. God hath seen mine affliction and the labour of my hands, and rebuked thee yesternight.', pt: 'Se o Deus de meu pai, o Deus de Abraão e o temor de Isaque não fossem comigo, certamente já me terias mandado embora de mãos vazias. Deus viu a minha aflição e o trabalho das minhas mãos, e te repreendeu ontem à noite.' },
    { v: 43, en: 'And Laban answered and said unto Jacob, These daughters are my daughters, and these children are my children, and these cattle are my cattle, and all that thou seest is mine: and what can I do this day unto these my daughters, or unto their children which they have born?', pt: 'E respondeu Labão e disse a Jacó: As filhas são minhas filhas, e os filhos são meus filhos, e o gado é o meu gado, e tudo o que vês é meu; e o que posso eu fazer hoje a estas minhas filhas, ou aos seus filhos que deram à luz?' },
    { v: 44, en: 'Now therefore come thou, let us make a covenant, I and thou; and let it be for a witness between me and thee.', pt: 'Agora, pois, vem, façamos uma aliança, eu e tu; e sirva de testemunho entre mim e ti.' },
    { v: 45, en: 'And Jacob took a stone, and set it up for a pillar.', pt: 'E Jacó tomou uma pedra e a erigiu como coluna.' },
    { v: 46, en: 'And Jacob said unto his brethren, Gather stones; and they took stones, and made an heap: and they did eat there upon the heap.', pt: 'E disse Jacó a seus irmãos: Ajuntai pedras; e eles tomaram pedras e fizeram um montão; e comeram ali junto ao montão.' },
    { v: 47, en: 'And Laban called it Jegarsahadutha: but Jacob called it Galeed.', pt: 'E Labão chamou-lhe Jegar-Saadutá; mas Jacó chamou-lhe Galeade.' },
    { v: 48, en: 'And Laban said, This heap is a witness between me and thee this day. Therefore was the name of it called Galeed.', pt: 'E disse Labão: Este montão é testemunha entre mim e ti hoje. Por isso foi chamado o seu nome Galeade.' },
    { v: 49, en: 'And Mizpah; for he said, The LORD watch between me and thee, when we are absent one from another.', pt: 'E também Mizpá; porque disse: Atente o Senhor entre mim e ti, quando estivermos ausentes um do outro.' },
    { v: 50, en: 'If thou shalt afflict my daughters, or if thou shalt take other wives beside my daughters, no man is with us; see, God is witness betwixt me and thee.', pt: 'Se afligires as minhas filhas, ou se tomares outras mulheres além das minhas filhas, nenhum homem está conosco; veja, Deus é testemunha entre mim e ti.' },
    { v: 51, en: 'And Laban said to Jacob, Behold this heap, and behold this pillar, which I have cast betwixt me and thee.', pt: 'E disse Labão a Jacó: Eis este montão, e eis esta coluna que ergui entre mim e ti.' },
    { v: 52, en: 'This heap be witness, and this pillar be witness, that I will not pass over this heap to thee, and that thou shalt not pass over this heap and this pillar unto me, for harm.', pt: 'Este montão é testemunha, e esta coluna é testemunha, de que eu não passarei este montão a ti, e de que tu não passarás este montão e esta coluna a mim, para mal.' },
    { v: 53, en: 'The God of Abraham, and the God of Nahor, the God of their father, judge betwixt us. And Jacob sware by the fear of his father Isaac.', pt: 'O Deus de Abraão e o Deus de Naor, o Deus de seu pai, julgue entre nós. E Jacó jurou pelo temor de seu pai Isaque.' },
    { v: 54, en: 'Then Jacob offered sacrifice upon the mount, and called his brethren to eat bread: and they did eat bread, and tarried all night in the mount.', pt: 'E Jacó ofereceu um sacrifício no monte, e chamou os seus irmãos a comer pão; e comeram pão e ficaram a noite no monte.' },
    { v: 55, en: 'And early in the morning Laban rose up, and kissed his sons and his daughters, and blessed them: and Laban departed, and returned unto his place.', pt: 'E Labão se levantou de madrugada e beijou seus filhos e suas filhas, e os abençoou; e Labão partiu e voltou ao seu lugar.' },
  ],
};
